window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q09"]=window.__LIBQ["tien-nghich"]["q09"]||{};window.__LIBQ["tien-nghich"]["q09"]["cotTruyen"]=[{"chuong":1064,"tieuDe":"Thác Sâm Xuất Hiện","tomTat":"Huyết long thi triển Hắc Dạ Thần Thông bao trùm hư vô trong bóng tối, Vương Lâm cưỡng ép thái sơ lực trong Tàn Dạ Thần Thông phá khai màn đêm nhưng đổi giá thiêu đốt nguyên lực, nguyên thần và thân thể. Vương Lâm lao vào vết thương huyết long, thu được khối tinh thể tâm huyết Cổ Thần vào không gian trữ vật. Nguyên thần sắp tiêu tan, được lão già áo đen bước tới cứu, vỗ mi tâm truyền sức mạnh phục hồi toàn diện bằng phương thức nghịch thiên, khen hắn thông minh và nhìn thấu mục đích phân thân. Lão già phá cơn lốc xoáy trên không, lộ ra thế giới đỏ máu và Thác Sâm đứng trên cột đá — tóc đỏ mắt đỏ, bát tinh Cổ Thần vương tộc, cuồng ngạo đỉnh thiên. Thác Sâm khinh miệt Viêm Lôi Tử là rác rưởi, Bát Vương Thi Âm Tông ngay cả rác rưởi cũng không bằng. Thác Sâm giao chiến lão già áo đen: quyền thứ nhất xé hư vô thành hai, quyền thứ hai phá tan thế giới băng, tuyên bố bộ tộc Cổ Thần không tu quy tắc mà phá vỡ quy tắc. Thác Sâm nhìn Vương Lâm rồi thân thể tiêu tan, lão già áo đen nói tiếp theo mới là sức mạnh thật sự của Cổ Thần rồi bước vào lốc xoáy mới, Vương Lâm không do dự bước theo. Bên trong khe không gian, thân thể to lớn của Đồ Ti ngón tay khẽ động, đôi mắt đã nhắm từ rất lâu lần đầu tiên chậm rãi mở ra."},{"chuong":1065,"tieuDe":"Sức Mạnh Của Cổ Thần","tomTat":"Cổ Thần Thác Sâm thức tỉnh từ giấc ngủ vĩnh hằng trong khe không gian, thân thể to bằng mấy tu chân tinh, tám tinh điểm trên mi tâm lần lượt phát sáng. Hắn tự xưng danh rồi vung tay quét chết một tu sĩ Toái Niết Sơ Kỳ tu đạo vạn năm dễ dàng như đuổi côn trùng, hút nguyên lực qua vết nứt trên cánh tay. Vương Lâm bị thanh âm Thác Sâm gây thương tổn nặng — thân thể nứt nẻ, nguyên thần tổn hại, có dấu hiệu hóa nham thạch. Lão già áo đen là người duy nhất đối đầu được, đánh văng cánh tay Cổ Thần và lưu thủ ấn đen, nhưng lui bảy bước mặt tái nhợt, nhận xét chỉ Không Niết mới giao chiến được vương tộc bát tinh. Thác Sâm đứng dậy phản công mãnh liệt, tinh điểm thứ ba phát sáng, Vương Lâm nhận ra đó liên quan đến bí thuật Khánh Không Luyện Tinh nhờ truyền thừa Cổ Thần nhưng không biết cách thi triển. Cuối chương lão già áo đen quát gọi Vô Cực Tử hiện ra, nhắc đến ước định năm xưa giữa hai người."},{"chuong":1066,"tieuDe":"Trốn Tới Nơi Đất Khách","tomTat":"Bên trong tinh điểm thứ tư trên mi tâm Thác Sâm, Vô Cực Tử đã dung hợp nửa thân với mặt đất, hối hận thừa nhận năm xưa tham lam sức mạnh vương tộc Cổ Thần muốn đột phá Không Niết Sơ Kỳ nên mới rơi vào cảnh bị giam. Lão già áo đen rút thanh kiếm gãy phun máu kích hoạt, xuyên thấu chân phải Thác Sâm, nhưng tu sĩ xương khô từ tinh điểm thứ ba bước ra dùng hai ngón tay kẹp kiếm đẩy bay — sức mạnh khiến quy tắc trời đất biến đổi. Thác Sâm triệu hồi Diệt Thần Mâu — vũ khí thật sự của vương tộc Cổ Thần, to lớn như tinh cầu — ném về phía lão già áo đen. Phân thân Vương Lâm lao ra trước Diệt Thần Mâu, thân thể sụp đổ, phun thần niệm lên mâu khiến nó chậm lại một khoảnh khắc rồi nguyên thần bị tiêu diệt. Thác Sâm nói tinh điểm thứ nhất Cổ Thần để lại cho Vương Lâm, ám chỉ sẽ nuốt hắn. Khoảnh khắc trì hoãn đó cho phép lão già áo đen nhảy vào vòng xoáy thoát, quay lại ôm Viêm Lôi Tử bị dư lực mâu trọng thương hai chân nổ tung. Bát Vương Thi Âm Tông nhảy vào vòng xoáy nhưng dư lực giết sáu người, hai vương cuối được Chủ Tôn cứu. Bổn tôn Vương Lâm tỉnh dậy trên nguyệt tinh ngoài Chu Tước Tinh, thu nữ thi, phá trận pháp, thi triển Súc Địa Thành Thốn bỏ trốn, nhận ra vĩnh viễn không thể quay về Liên minh Tinh Vực, chạy đến tinh cầu hoang đã bố trí trận pháp trước khi đến Tứ Thánh Tông."},{"chuong":1067,"tieuDe":"Tuyết","tomTat":"Trên một tinh cầu yên bình trong Liên Minh Tinh Vực, giữa đêm tuyết đại lễ, Vương Lâm một mình đi trong gió tuyết tới bình nguyên, quét sạch tuyết ngàn trượng lộ ra trận pháp truyền tống cực lớn. Hắn dùng nguyên thần hôn mê làm vật dẫn kích hoạt trận pháp, tạo thông đạo tối đen. Quay đầu nhìn lại, hắn cảm nhận hương vị quê nhà và hơi thở bằng hữu, nói rằng lần này đi không biết khi nào trở về, rồi cười dài bước vào vòng xoáy rời khỏi Liên Minh Tinh Vực. Chương giới thiệu cấu trúc tứ đại Tiên Giới: Vũ Giới có Liên Minh Tinh Vực, Lôi Giới có La Thiên Tinh Vực, Phong Giới có Vân Hải Tinh Vực — tinh vực lớn nhất, tràn ngập tinh vụ vĩnh hằng, chia chín bậc đồng tâm. Đích đến là đại lục Mạc La ở bậc thứ năm Vân Hải, trung tâm có tòa tháp đen ngăn sương mù. Tại rừng phía bắc Mạc La, trận pháp tiếp nhận phát sáng lam trong đêm mưa sấm sét, báo hiệu một người khiến tu sĩ tứ đại Tiên Giới khiếp sợ sắp xuất hiện."},{"chuong":1068,"tieuDe":"Mưa","tomTat":"Ở phía đông đại lục Mạc La trong Vân Hải Tinh Vực, phân tông Quy Nguyên Tông chìm trong cơn mưa tang thương khi vị chưởng môn già hấp hối. Lão tiết lộ bản thân bị hút tuổi thọ ở Linh Nguyên Tông tầng thứ tám, dặn bốn đệ tử thân truyền gánh vác tông môn và giao rắn Ngũ Giai Tử Mục làm thú trấn tông. Trước khi chết, lão thiêu đốt nguyên thần thi triển thần thông truyền thừa Trạch Linh quét toàn đại lục tìm Bạn Linh Tử nhưng thất bại. Đúng lúc sắp tan biến, thần thức lão phát hiện Vương Lâm vừa xuất hiện từ Truyền Tống Trận ở khu rừng phía Bắc — nhìn thấy vô số oan hồn bao quanh hắn, lão kinh hãi tột độ, chỉ kịp hét bốn chữ di ngôn trước khi nguyên thần sụp đổ quy tiên. Bốn đệ tử hiểu lầm di ngôn là manh mối Bạn Linh Tử, phát lệnh toàn tông đi phía Bắc tìm người tóc trắng. Vương Lâm hít thở không khí Vân Hải, bước sâu vào khu rừng, chính thức mở ra hành trình tại tinh vực mới."},{"chuong":1069,"tieuDe":"Tằng Ngưu","tomTat":"Phân thân Vương Lâm đi trong rừng đầm lầy Vân Hải, quyết định đứng vững tại đây thay vì trốn chạy Thác Sâm, chờ bổn tôn vượt tam tổn thất kiếp. Hắn biến đổi tướng mạo thành thư sinh tầm thường tóc đen, giả danh họ Tằng, đi ra khỏi khu rừng. Vương Lâm cứu Lão Tam khỏi rắn độc cắn, được đại hán Vũ Đại cho ở nhờ tại Bắc Thủy Thôn phía Bắc đại lục Mạc La. Hắn sống một tháng với thân phận lang trung chữa bệnh và thợ khắc gỗ, hòa nhập với thôn dân. Tu sĩ Triệu Ngọc thuộc Quy Nguyên Tông đến thôn tuyển đệ tử, bắt dân đứng dưới mưa lạnh. Vương Lâm bước ra khiến Triệu Ngọc sửng sốt bối rối, lập tức cho dân về, rồi kín đáo phóng hơi nóng xua hàn khí cho thôn dân. Quy Nguyên Tông tuyển được 31 phàm nhân trên toàn Mạc La trong một tháng, đưa về sơn môn phía Đông. Đại trưởng lão Lữ Yên Phi thu nhận bảy người, trong đó có Tằng Ngưu từ Bắc Thủy Thôn — chính là Vương Lâm trà trộn vào tông môn."},{"chuong":1070,"tieuDe":"Quy Nguyên Tông","tomTat":"Tại Nam Uyển Quy Nguyên Tông, Lữ Yên Phi — đệ nhất mỹ nữ tu vi Khuy Niết Hậu Kỳ đại viên mãn — đau buồn vì sư tôn Tịch Niết viên mãn đã quy tiên, khiến tông phái lâm vào suy yếu nhất. Nàng cầm ngọc giản màu tím liên quan tới Lô Địch, thề chết cũng không chịu song tu với hắn. Nàng phân bốn thiếu niên phàm nhân cho đại đệ tử và tam đệ tử, yêu cầu Tử Mục Mãng kiểm nghiệm tư chất. Vương Lâm giả dạng phàm nhân Tằng Ngưu được nhị đệ tử Tôn Vân đưa về khu vườn dược thảo Nam Uyển, tự xưng lang trung, nhận ra nhiều loại dược thảo đã tuyệt chủng. Đêm xuống hắn tách bổn tôn khỏi phân thân — nửa thân dưới chỉ còn xương đen xen tia đỏ, thương thế nặng hơn lúc ở Chu Tước Thánh Tông do sức mạnh Cổ Thần cạn kiệt. Hắn suy ngẫm về thật và giả, nắm chút ý niệm về đạo, rồi kinh ngạc trước thuật luyện đan Vân Hải có đan dược vượt Vấn Đỉnh, nảy ra giả thuyết có thể tồn tại đan dược trợ cảm ngộ ý cảnh. Tôn Vân lo lắng sư tôn bị dòm ngó, liều mạng đột phá Dương Thực nhưng thất bại, nguyên thần bị thương, quyết uống Nhập Tử Ly Hồn Đan. Đúng lúc đó Vương Lâm truyền âm một chữ Định ngăn nàng lại."},{"chuong":1071,"tieuDe":"Lữ Yên Phi","tomTat":"Đại lục Mạc La vào mùa mưa, Vương Lâm cầm ô lên đỉnh núi Quy Nguyên Tông cảm thụ thiên địa. Tu vi Tịnh Niết của hắn dung hợp với trời đất, lại có một tia bổn nguyên và từng cảm thụ bước thứ ba, nên không ai trên đại lục nhìn ra. Trên đỉnh núi, hắn gặp nữ trưởng lão Lữ Yên Phi, xưng tên giả Tằng Ngưu. Nàng kể về sư tôn: mười ba tuổi bái sư, sư tôn tự luyện Man Thiên Đan giúp nàng Vấn Đỉnh, dẫn nàng ba năm bắt cáo đỏ sáu mắt làm bản mệnh linh thú. Sư tôn bị Tử Đạo Tông hại quy tiên, thiếu tông chủ Lô Địch gửi ngọc giản ép nàng song tu, đe dọa tâu Chủ Tông khai chiến, ba sư huynh hèn nhát muốn hy sinh nàng. Lữ Yên Phi đánh giá Tằng Ngưu kiên định phi thường, rồi mặt nàng lộ vẻ kiên định và sát khí. Vương Lâm quay về phòng, nhớ lại ký ức Triệu Ngọc về đặc điểm Vân Hải Tinh Vực và đặc biệt hứng thú với Man Thiên Đan — đan dược trợ giúp Vấn Đỉnh."},{"chuong":1072,"tieuDe":"Tinh Hồn","tomTat":"Vương Lâm bí mật dùng Định Thân Thuật khống chế Tôn Vân đang tu luyện, lấy viên đan dược màu đen từ tay nàng để phân tích bằng thần thức, phát hiện bên trong chứa tinh hồn một con vượn đen linh thú đã sống hơn ba ngàn năm bị phong ấn trói buộc. Sau khi đặt đan lại và giải thuật, Tôn Vân nuốt Nhập Tử Ly Hồn Đan, nguyên thần bị ngọn lửa thiêu đốt đồng thời con vượn đen mắt vàng xông ra xé rách nguyên thần, nàng cố luyện hóa nhưng dần rơi vào tuyệt vọng vì tốc độ luyện hóa chậm hơn tốc độ bị hủy diệt. Vương Lâm quyết định cho nàng một cơ hội, điểm một chỉ vào thiên linh Tôn Vân, thần thức hóa thân ảnh áo trắng tóc bạc tiến vào tâm thần nàng, chỉ tùy ý tung ra một chỉ đánh tan con vượn đen khiến nó bị luyện hóa hoàn toàn. Hồn lực con vượn dung nhập nguyên thần Tôn Vân, mang theo cảm ngộ sâu sắc về trời đất, giúp nàng mở cửa lớn tiến vào cảnh giới Dương Thực dù chưa chính thức đạt tới. Tôn Vân tỉnh lại không thấy ai nhưng không thể quên hình ảnh người tóc bạc, nàng chợt nhớ tới di ngôn sư tổ trước khi quy tiên sau khi thi triển thần thông Trạch Linh chỉ nói một câu phía bắc tóc trắng, liền lập tức bay đến tẩm cung sư tôn Lữ Yên Phi. Trong khi đó Vương Lâm đứng bên cửa sổ suy ngẫm về loại đan dược dùng hồn phách linh thú trợ giúp cảm ngộ ý cảnh vốn hoàn toàn khác biệt với hai giới Lôi Vũ, liên tưởng tới tinh hồn mà Mặc Trí từng đưa cho hắn ở Chu Tước Thánh Tông. Ở tầng năm Vân Hải Tinh Vực gần đại lục Mạc La, một thanh niên áo tím tà khí ngút trời cưỡi mãnh thú khổng lồ tuyên bố muốn biến Lữ Yên Phi thành thê thiếp lô đỉnh và chiếm Quy Nguyên Tông làm tẩm cung, lão giả Tống thúc theo hầu bình thản khẳng định lão đạo kia đã chết nên mười phần nắm chắc."},{"chuong":1073,"tieuDe":"Tử Khí Tây Lai","tomTat":"Vương Lâm ở Quy Nguyên Tông mười ngày, ban ngày giả phàm nhân đọc mộc giản Điển Tịch Các tìm hiểu lịch sử đại lục Mạc La và Vân Hải Tinh Vực. Tôn Vân âm thầm điều tra ba mươi mốt phàm nhân phương bắc nhưng không thu hoạch, sư tôn Lữ Yên Phi thi triển thần thông cũng bất thành. Tôn Vân đến phòng Vương Lâm trách móc chuyện chăm dược thảo, nhưng đối mặt ánh mắt hắn thì run sợ nuốt lời, nhận ra phong thái giống người áo trắng hôm trước. Đêm khuya Vương Lâm đột nhập đạo quán bí mật treo giữa không trung trên tám cột đá, phá cấm chế trên giá di bảo, nghiên cứu ngọc giản lão tổ Quy Nguyên Tông phần linh thú và luyện đan, chứng thực phỏng đoán về phương pháp luyện đan Vân Hải qua Ly Hồn Đan cấp tám (phế đan). Hắn không lấy di bảo, quyết tâm tự dùng phương pháp luyện đan Vân Hải nâng tu vi. Cuối chương, biên giới phía tây đại lục Mạc La bị tấn công, kết giới phòng hộ do hắc tháp phát ra sụp đổ trong tiếng nổ kinh thiên, một mãnh thú hình nòng nọc khổng lồ trăm trượng xâm nhập, trên lưng là lão già vẻ mặt kiệt ngạo tay phải có tử phong vờn quanh."},{"chuong":1074,"tieuDe":"Cầu Vồng","tomTat":"Thiếu tông chủ áo tím của Tử Đạo Tông cùng Tống Ngũ Đức (Tịnh Niết Trung Kỳ) cưỡi linh thú khổng lồ bay vào đại lục Mạc La tuyên bố chiếm Quy Nguyên Tông, nhân lúc lão tổ vừa quy tiên. Tứ đại trưởng lão Quy Nguyên Tông — Lý Hướng Đông, Lữ Yên Phi cùng hai trưởng lão tây-bắc — dẫn đệ tử hóa cầu vồng bay ra quyết tử nghênh chiến dù biết không phải đối thủ. Tôn Vân trong mưa gió nhớ lại hai thân ảnh Vương Lâm chồng lên nhau. Vương Lâm từ đạo quán quan sát, suy tính rằng Quy Nguyên Tông bị diệt sẽ ảnh hưởng đường tu, quyết định ra tay. Hắn chặn đường linh thú, lần lượt thi triển Sát Lục Khí, tiên thuật Hoán Vũ, thần thông Định rồi rút Không Niết Kiếm chém một nhát — giết Tống Ngũ Đức trong nháy mắt, hình thần câu diệt. Thiếu tông chủ kinh hoàng cưỡi linh thú chạy trốn, bị Vương Lâm truy đuổi. Trời sáng mưa tạnh, cầu vồng hiện giữa trời, thân ảnh trắng của Vương Lâm đuổi theo linh thú in sâu trong con ngươi Lữ Yên Phi."},{"chuong":1075,"tieuDe":"Một Sợi Lông","tomTat":"Vương Lâm giết Lô Địch (thiếu tông chủ Tử Đạo Tông, tu vi Âm Hư) bằng một ngón tay điểm vào mi tâm, bảo mệnh pháp bảo đóa sen đen chưa kịp kích hoạt đã vô dụng. Hắn thu đóa sen đen, túi trữ vật và linh thú đen của Lô Địch rồi bước một bước biến mất ở chân trời, từ đầu tới cuối Quy Nguyên Tông không ai nhìn thấy mặt. Tứ đại trưởng lão Quy Nguyên Tông nhắc lại di ngôn sư tôn trước khi quy tiên — bốn chữ “Phía bắc, tóc bạc” — khẳng định vị tiền bối tóc bạc chính là người được nhắc tới. Lữ Yên Phi tin tưởng vị tiền bối sẽ giúp lần nữa, chủ động dùng ám lực hủy diệt cuốn tranh cổ trong túi trữ vật. Tôn Vân về sơn môn nói nhỏ với sư tôn rằng Vương Lâm đang ở đây. Tại đại lục tím (căn cứ Tử Đạo Tông, tầng 5 Vân Hải), tông chủ Lô Vân Tòng mặc tử kim bào dùng tử quang bắt sống và luyện hóa tinh hổ thú trăm trượng để luyện Hổ Cốt Hồn Đan, lão già áo tím chúc mừng nói đan dược sắp thành. Tác giả nhấn mạnh sự uy hiếp của Tử Đạo Tông so với các thân phận của Vương Lâm chỉ là trò đùa, còn không bằng một sợi lông trên người Thác Sâm."},{"chuong":1076,"tieuDe":"Hy Vọng Nghịch Thiên Viên Mãn Lần Thứ Hai","tomTat":"Tông chủ Tử Đạo Tông Lô Vân Tòng đang ngoài tinh vụ thì ngọc giản bảo mệnh vỡ nát, tàn hồn con trai Lô Địch hiện ra với vẻ sợ hãi rồi tiêu tan trước mặt ông. Lô Vân Tòng bình tĩnh đáng sợ, tự vạch trần tội ác mê nữ sắc hại nữ đệ tử nhiều tông phái của con, nhưng vẫn tuyên bố sẽ chôn Lữ Yên Phi theo con và giết kẻ đã hạ sát Lô Địch. Khi lão già áo tím tiết lộ Lô Địch muốn lấy Thiên Âm Phiên ở Tử Vân Hải để phong ấn hồn phách nữ tử nuôi âm tiên, Lô Vân Tòng nổi giận dữ dội. Tại Quy Nguyên Tông, Lữ Yên Phi cùng đệ tử Tôn Vân đến nhà gỗ Vương Lâm, kể chuyện sư thúc tổ Lữ Tử Đạo — tổ tiên ẩn cư nhà họ Lữ — để gián tiếp trao cho Vương Lâm thân phận 'Lữ Tử Hạo' giúp hắn ẩn thân hợp lý. Vương Lâm nhận ra sự thông minh kín đáo của nàng, so sánh với Liễu Mi, Hồng Điệp, Lý Mộ Uyển rồi chấp nhận danh tính mới. Sau đó Vương Lâm nghiên cứu hoa sen đen, phát hiện là thực vật thiên nhiên bị phong ấn trận pháp đơn giản có thể tạo phòng hộ cực mạnh. Kiểm tra túi trữ vật Lô Địch, hắn tìm thấy cờ nhỏ màu vàng chứa mấy trăm âm hồn nữ tử và thú hồn hình rắn phát ra khí tức cực âm — dù chưa hoàn chỉnh nhưng đây chính là mảnh ghép cuối còn thiếu để Thiên Nghịch Châu viên mãn lần thứ hai."},{"chuong":1077,"tieuDe":"Sự Đau Lòng Của Tôn Vân","tomTat":"Vương Lâm xem xét chiến lợi phẩm thu từ Lô Địch: phá trận pháp trong cờ nhỏ màu vàng giải phóng âm hồn nữ tử bị giam cầm, phong ấn cực âm hồn lại; nhận định phương pháp nuôi cực âm bằng âm hồn là sai lầm, nhớ lại Thiên Vận Tử năm xưa mượn thân thể Bạch Vi để cực âm đạt đỉnh chuyển thành cực dương mới là chính đạo. Hắn khám phá bình ngọc tím chứa ba viên đan dược tử quang bí ẩn và nhận ra cây hương to bằng cánh tay trẻ con chính là vật tu sĩ Vân Hải dùng mê hoặc Văn Thú năm xưa. Mùa mưa kết thúc, Vương Lâm đã quen sinh hoạt tại Quy Nguyên Tông. Tôn Vân dùng trực giác nhận định Tằng Ngưu chính là người áo trắng đã cứu nàng, cung kính dạy hắn nhận biết dược thảo Vân Hải Tinh Vực. Vương Lâm hỏi về Vụ Trung Hoa — dược liệu luyện Ly Hồn Đan tầng sáu trở lên — được biết chỉ mọc ở đại lục hoang dã ngoài tinh vực, trong tông chỉ có ba cây hoa khô ở chỗ Lý sư thúc. Hắn hái dược thảo từ vườn Tôn Vân, dùng Thiên địa chi hỏa tạo hỏa cầu thay lò luyện để luyện đan dược tầng ba, nhưng đan tạc lần đầu. Tôn Vân rất đau lòng vì vườn dược thảo là công sức của nàng và sư tôn, thiện cảm với Vương Lâm giảm phân nửa."},{"chuong":1078,"tieuDe":"Man Hoang Đại Lục","tomTat":"Vương Lâm luyện đan mười sáu lần trong ba ngày trên Mạc La, chỉ lần đầu và lần cuối thành công, luyện được một viên đan dược cấp ba. Tôn Vân đau xót vì dược viên tâm huyết nhiều năm gần như bị phá sạch mà chỉ ra đan dược cấp ba, hét đòi trả dược thảo nhưng Vương Lâm đã biến mất. Vương Lâm phá tầng phòng hộ Mạc La, bay vào biển mây tinh cầu hướng đến Man Hoang đại lục — nơi không có hắc tháp bảo hộ, nhiều mãnh thú và dược thảo quý. Trên đường đi gặp nhiều loại mãnh thú kỳ dị, tất cả đều sợ hãi tránh xa phạm vi thần thức của hắn. Hắn thả hơn mười con Văn Thú ra bay lượn, cưỡi Văn Thú vương xuyên sương mù ba ngày đến Man Hoang đại lục. Đặt chân lên mặt đất cát đen bóng, phát hiện thành trì phàm nhân đổ nát với vết máu khô trên tường, một bóng đen từ đống đổ nát lao ra tấn công hắn với tốc độ cực nhanh."},{"chuong":1079,"tieuDe":"Điều Động Và Điều Khiển","tomTat":"Vương Lâm đã ở Man Hoang đại lục bảy ngày, chém nhiều mãnh thú lấy linh hồn và dược thảo. Cùng bầy Văn Thú hộ tống, hắn tiến lên đỉnh một ngọn núi xanh đen hiểm trở nơi khỉ đen khổng lồ cấp năm (thân trăm trượng) ngồi khoanh chân. Khỉ đen triệu tập mãnh thú tấn công; Vương Lâm dùng phi kiếm tạo kiếm trận mở đường, thu cây đại thụ tím có hai quả trắng đen biến hóa kỳ dị vào khe trữ vật, rồi dùng khí sát lục đánh tan lốc xoáy của khỉ đen. Trong lúc chiến đấu, hắn nhớ lại cảnh lão giả hắc y Đệ Tam Bộ trên La Thiên vung tay ngăn chưởng Cổ Thần Thác Sâm, minh ngộ rằng không phải điều động mà là điều khiển nguyên lực thiên địa — cưỡng ép nguyên lực bốn phương hóa công kích toàn bạo, đánh bật khỉ đen, ba khe nứt lan khắp toàn thân nó. Khỉ đen dưới nguy cơ đột phá lên cấp sáu, hiện thần thông Tụ hồn vào thân. Vương Lâm ấn tay ép linh hồn quay về, dùng Khống Linh Ấn thu phục khỉ đen làm linh thú, cưỡi nó phóng đi như lưu tinh."},{"chuong":1080,"tieuDe":"Kinh Biến","tomTat":"Tinh vực cấp năm Vân Hải bất ngờ hỗn loạn khi hơn mười luồng cầu vồng chở tu sĩ từ tinh vực cấp sáu ồ ạt xâm nhập, tất cả hướng về Man Hoang đại lục. Cùng lúc, Vương Lâm bình thản ngồi trên vai khỉ đen khổng lồ di chuyển trên phía bắc Man Hoang, thu dược thảo mà khỉ đen đoạt từ hang chim ưng giữa thủy triều hơn mười vạn mãnh thú truy kích. Ở một sơn cốc khác trên đại lục, Thi Lạc Hình — đệ tử Hoa Thanh Tông cấp sáu, tu vi Tịnh Niết hậu kỳ — đang bị thương trúng độc, bị lão bà Ngũ Độc Môn dùng trận pháp tám đầu lâu dẫn động tử hồn vây khốn. Mười chín đệ tử của lão chỉ còn bốn. Lão bà uy hiếp giao nộp vật phẩm và tiết lộ nguyên nhân cuộc truy đuổi: Thi Lạc Hình đã lén vào tinh vực cấp ba tìm được ngọc giản của Phá Thiên Tông tinh vực cấp tám, chứa phương pháp bào chế Niết Không Đan trong truyền thuyết — khiến gần như toàn bộ tông phái tinh vực cấp sáu điên cuồng truy đuổi."},{"chuong":1081,"tieuDe":"Tới Nhanh Lắm!","tomTat":"Vương Lâm ở lại Man Hoang đại lục vài ngày, lợi dụng con khỉ đen liên tục xông vào sào huyệt mãnh thú cướp đoạt dược thảo khắp đại lục. Con khỉ nổi danh vì thói cướp đoạt lâu năm, đám mãnh thú thấy nó liền điên cuồng truy đuổi tạo thành cơn thủy triều mãnh thú. Vương Lâm dán bùa vàng tăng tốc cho con khỉ, nhưng nó quay lại quậy phá đoàn thú rồi mới chịu chạy. Con khỉ đen xông thẳng vào khu vực trung tâm đại lục — nơi toàn sơn cốc sương mù, khí tức âm trầm, mãnh thú bí ẩn biến mất. Tại đây Vương Lâm phát hiện trận pháp tám đầu lâu khổng lồ hấp thu tử hồn do Ngũ Độc Môn bày ra bao vây sơn cốc. Lão bà Ngũ Độc Môn (Tịnh Niết trung kỳ, độc công vượt xa đồng cấp) hiểu lầm Vương Lâm là viện binh đối thủ, chủ động tấn công để độc chiếm ngọc giản và đan phương Niết Không Đan. Hai bên giao chiến: Vương Lâm thi triển hắc long cuồng phong, lão bà đáp trả bằng ba luồng khí độc, thần thông Độc Linh Ẩn triệu hồi tượng Độc Vương và thả linh thú rắn đen mào gà."},{"chuong":1082,"tieuDe":"Trong Sơn Cốc","tomTat":"Vương Lâm phản kích lão bà Ngũ Độc Môn bằng tiên thuật Hô Phong hóa năm Hắc Long dung hợp thành trường thương đen truy kích, đồng thời thu nguyên lực thiên địa trong nghìn trượng vào đầu ngón tay phá hủy Ấn Độc và pho tượng hư ảo của bà ta, tiếng nổ chấn động cả Man Hoang đại lục. Hắn thả Ngân Y Nữ Thi ra chiến đấu với con rắn đầu mào gà rồi thi triển Định Thân Thuật trói lão bà, khiến máu độc phản phệ thối rữa toàn thân, trường thương đen xuyên ngực nổ tung giết chết bà ta, nguyên thần bị thu. Sau trận chiến, Vương Lâm phong ấn tám đầu lâu trận pháp thành khô lâu xám nhỏ giữ khả năng khôi phục, rồi tiến vào sơn cốc. Bên trong hắn phát hiện thi thể đàn ông và tại trung tâm gặp nam tử trung niên Tịnh Niết hậu kỳ trúng kịch độc Ngũ Độc Môn cùng bốn thi thể đệ tử. Nam tử trung niên xin Vương Lâm cho mượn nguyên lực mở túi trữ vật lấy ngọc giản và phương pháp luyện đan giao lại, đổi cái chết thống khoái. Vương Lâm đồng ý phóng nguyên lực nhưng khi gần ba tấc cơ thể người kia, nguyên lực đột nhiên biến đổi bất thường."},{"chuong":1083,"tieuDe":"Làm Chuyện Đại Sự Phải Bình Tĩnh","tomTat":"Vương Lâm dùng thiết kiếm chém đứt đầu tên đàn ông trung niên Tịnh Niết hậu kỳ khi hắn định tự bạo. Phân tích kỹ hiện trường sơn cốc, Vương Lâm nhận ra bốn thi thể đệ tử bị tên đàn ông trung niên giết chứ không phải chết vì độc, xác định lời hắn nói không còn nguyên lực là dối trá. Suy luận vật quý không trong túi trữ vật mà giấu trong xác đệ tử, Vương Lâm dùng lửa từ mắt trái luyện hóa hài cốt, tìm được ngọc giản ghi Phá Thiên Tông cấp tám và mảnh xương thú ghi đan phương Niết Không đan — đan dược giúp nắm chắc đột phá Đệ Tam Bộ, vượt suy kiếp Thiên Nhân, tiến cảnh giới Nhập Thần. Nhận ra giá trị vật này đủ gây kiếp nạn cho Tu Chân giới, Vương Lâm phi tang hiện trường, tạo giả tượng Độc Bà Tử đã lấy đan phương rồi độc chiếm bỏ trốn, bắt giữ nguyên thần bà ta không cho chết. Thu Ngân Y Nữ Thi và bảy đầu lâu, Vương Lâm dùng Súc Địa Thành Thốn, bùa vàng, da thú tăng tốc phóng rời Man Hoang đại lục. Sau đó ngồi trên vai khỉ đen ngụy trang bình thản hướng về Quy Nguyên Tông trên Mạc La đại lục, nhưng cuối chương phát hiện nhiều luồng cầu vồng đang tiến đến gần."},{"chuong":1084,"tieuDe":"Hết Sức Căng Thẳng","tomTat":"Trưởng lão Hoa Thanh Tông Tiền Quý Chung dẫn đám đệ tử hạch tâm cưỡi mãng xà hình rồng bay về Man Hoang đại lục cứu viện đại đệ tử Thi Lạc Hình. Chương hồi ức lại đại chiến mười vạn tám ngàn năm trước: Phá Thiên Tông phát hiện khe nứt không gian chứa hài cốt bí ẩn kèm ba bảo vật, trong đó mảnh xương thú ghi phương pháp luyện Niết Không Đan, dẫn đến toàn Vân Hải Tinh Vực tranh đoạt, Phá Thiên Tông phân liệt, mảnh xương thú biến mất. Vài tháng trước, đệ tử Hoa Thanh Tông tình cờ đoạt được manh mối, tông phái bí mật cử Thi Lạc Hình đi tinh vực cấp ba chứng thực. Hắn lấy được mảnh xương thú nhỏ và ngọc giản nhưng trên đường về bị Ngũ Độc Môn đuổi giết, thẻ sinh mệnh trong Tập Anh Các đã vỡ vụn xác nhận tử vong. Tiền Quý Chung chấn động, theo nguyên tắc thà giết lầm không bỏ sót, hạ lệnh tám đệ tử bắt Vương Lâm đang giả tu vi Khuy Niết trung kỳ cưỡi khỉ đen gần đó, mang đến Man Hoang đại lục."},{"chuong":1085,"tieuDe":"Liên Trảm","tomTat":"Vương Lâm nhận ra nếu quay về Man Hoang đại lục, khỉ đen sẽ khiến mãnh thú náo động lộ tung tích, kết hợp nghi vấn cái chết Thi Lạc Hình sẽ khiến các tông phái truy vấn, nên quyết ra tay giết sạch mười tám đệ tử hạch tâm Hoa Thanh Tông. Hắn thi triển Hô Phong thuật hóa năm Hắc Long diệt năm tên Dương Thực, dùng ngón tay điểm mi tâm giết hai tên Tịnh Niết, biển lửa thiêu ba tên, thanh quang chém một tên, Hoán Vũ tiểu kiếm xuyên bốn tên — tổng cộng mười bảy người chết trong nháy mắt, một nguyên thần kịp bóp nát ngọc giản bỏ chạy bị Hứa Lập Quốc truy kích. Tiền Quý Chung (Toái Niết) phản kích bằng thần thông hắc quang phá tầng phòng hộ sát lục, triệu trường thương đen bị Phong Tiên Ấn chặn, rút phất trần trắng thi triển quy tắc thiên địa hóa mưa kiếm bạch quang xuyên đùi phải Vương Lâm, nhờ khôi giáp đỏ máu huyễn hóa mới sống sót. Ngân Y Nữ Thi xuất hiện thu phục linh thú mất chủ. Vương Lâm triệu linh hồn Hư Không Tử và Thiên Vận Tử từ Phong Tiên Ấn, rút Thứ Không Niết (Thiết Kiếm) khiến tinh không chấn động, Tiền Quý Chung nhận ra bảo vật bùng tham vọng muốn đoạt, bùng phát tu vi Toái Niết chuẩn bị quyết chiến."},{"chuong":1086,"tieuDe":"Rời Khỏi Vòng Xoáy","tomTat":"Vương Lâm tung toàn lực đối đầu Tiền Quý Chung: phóng linh hồn Hư Không Tử và Thiên Vận Tử cầm chân đối phương, thi triển 19 kiếm Thứ Không Niết chém nát thân thể hắn thành 19 mảnh. Nguyên thần Tiền Quý Chung thoát ra cuốn phất trần bỏ chạy, tự bạo hai tay nguyên thần và phất trần, hấp thu hồn linh thú mãng xà duy trì nguyên thần. Vương Lâm hóa Chu Tước bằng Cửu Huyền Biến truy kích, rồi dung nhập linh hồn Thiên Vận Tử vào cơ thể mình (Tát Đậu Thành Binh đạt cực hạn), triệu hoán Một ngón tay Thiên Vận Tử tiêu diệt nguyên thần Tiền Quý Chung, linh hồn Thiên Vận Tử biến mất theo. Vương Lâm bị thương nặng, năm ngày sau thoát về Mạc La đại lục, trở lại dược viện Quy Nguyên Tông trị thương ba ngày rút hết tàn dư sợi tơ trắng. Tin Thi Lạc Hình chết lan ra khiến tinh vực bị phong tỏa, Hoa Thanh Tông kinh hoàng tìm hung thủ, Ngũ Độc Môn bị nghi oan. Vương Lâm vừa lấy chiến lợi phẩm định nghiên cứu thì cảm ứng bản tôn sắp độ kiếp, lập tức phóng đi."},{"chuong":1087,"tieuDe":"Nhất Tổn Lưỡng Kiếp","tomTat":"Chương giải thích chi tiết hệ thống Tam Tổn Thất Kiếp của tộc Cổ Thần gồm ba tầng kiếp nạn, trong đó Vương Lâm là Cổ Thần ngũ tinh đầu tiên gặp Tổn Kiếp — điều chưa có tiền lệ. Bản tôn Vương Lâm ngồi sâu dưới lòng đất Quy Nguyên Tông đã hoàn thành Tổn Kiếp đầu tiên (mất hết máu thịt) nhờ máu huyết Đồ Ti bị xương cốt hấp thu, khung xương phình lên ba trăm trượng. Cốt Kiếp bắt đầu: lực vô hình bóp nát xương từ chân lên, sau một tháng chân phải vỡ hoàn toàn, chân trái từ đầu gối xuống thành tro bụi. Vương Lâm tuyên ngôn ý chí nghịch thiên, quyết kiên trì đến khoảnh khắc cuối cùng mới phản kháng để khung xương ngưng tụ hoàn chỉnh. Chấn động từ lòng đất lan khắp Mạc La đại lục, kéo nguyên lực trời đất và tinh không về, khiến mãnh thú cấp năm đến cấp bảy tụ tập bên ngoài. Tứ đại trưởng lão Quy Nguyên Tông do Lý Hướng Đông dẫn đầu quyết định đi kiểm tra nguồn chấn động, Lữ Yến Phỉ bất an nhưng gật đầu đồng ý."},{"chuong":1088,"tieuDe":"Ngưng Tụ Thần Cốt","tomTat":"Lý Hướng Đông dẫn Lữ Yến Phỉ cùng hai lão già Quy Nguyên Tông xuyên đất tiến xuống nơi phát ra tiếng nổ ầm ầm, nhưng bị thần niệm bản tôn Vương Lâm tấn công hai lần khiến cả bốn phun máu văng ra ngoài. Lữ Yến Phỉ tiết lộ người dưới lòng đất chính là sư thúc tổ Lữ Tử Hạo đang tiềm tu. Trong lòng đất, bản tôn Vương Lâm bị cốt kiếp phá nát toàn bộ khung xương ba trăm trượng đến mảnh cuối cùng. Đúng khoảnh khắc tro cốt sắp tiêu tán hoàn toàn, phân thân bất chấp phản phệ trọng thương thi triển Định Thân Thuật khiến tro cốt ngừng lại. Khí tức cổ thần bùng ra, hút sạch nguyên lực thiên địa toàn Mạc La đại lục, phá vỡ tầng phòng hộ đại lục hút thêm nguyên lực bên ngoài tinh không, tro cốt ngưng tụ ngược thành xương mới cứng rắn vượt xa trước đây. Bản tôn ngưng tụ được xương đầu lâu và nửa thân trên, gầm rống tuyên chiến với trời. Tầng phòng hộ Mạc La đại lục tan vỡ, sương mù tràn vào, và một con sư tử khổng lồ hung thú cấp tám từ phương xa phóng về phía đại lục."},{"chuong":1089,"tieuDe":"Uy!","tomTat":"Khung xương nửa dưới bản tôn Vương Lâm ngưng tụ hoàn chỉnh, cốt kiếp tiêu tán, nhưng nhục kiếp (Nhất Tổn Nhị Kiếp) lập tức hàng lâm ngăn cản máu thịt tăng trưởng. Vương Lâm lấy ra máu vương tộc Cổ Thần đoạt được trước đó, dung nhập vào khung xương để máu thịt tái sinh. Mùi máu Cổ Thần khiến đám hung thú ngoài tinh không phát cuồng, đổ xô phóng về Mạc La đại lục. Bản tôn thu nhỏ về hình người bình thường, dung hợp với phân thân rồi phá đất xông lên, dùng nắm đấm giết liên tiếp hơn trăm mãnh thú cấp năm đến cấp bảy, hấp thu sinh cơ giúp máu thịt tăng trưởng. Cuối cùng Kiếm Sư Thú cấp tám xuất hiện, Vương Lâm một đòn húc nổ tan nó thành sương máu, hấp thu luồng sinh cơ khổng lồ. Lý Hướng Đông, Lữ Yến Phỉ và hai lão già Quy Nguyên Tông chứng kiến toàn bộ, hoàn toàn chấn động trước uy lực của Vương Lâm."},{"chuong":1090,"tieuDe":"Lý Thiến Mai","tomTat":"Vương Lâm một cước giết chết hung thú cấp tám rồi truy sát toàn bộ mãnh thú trong phạm vi hơn mười vạn dặm ngoài Mạc La đại lục, thu sinh cơ dung nhập bản tôn để chống nhục kiếp. Ba ngày sau, bản tôn vượt qua Nhất Tổn Nhị Kiếp đầu tiên của Cổ Thần Tam Tổn Thất Kiếp, chính thức thành Cổ Thần Ngũ Tinh hoàn chỉnh, tinh điểm thứ sáu mơ hồ hình thành và bản tôn bắt đầu diễn hóa Vọng Nguyệt. Vương Lâm đánh giá sau hợp thể có thể giết Toái Niết sơ kỳ nhưng còn chênh lệch lớn so với Toái Niết trung kỳ trở lên, quyết định nghiên cứu phương pháp luyện đan cấp cao. Cái chết của Thi Lạc Hình khiến tu sĩ tinh vực cấp sáu phân tán truy tìm, tin tức ngọc giản và phương pháp luyện đan truyền ra kinh động tinh vực cấp bảy và cấp tám, nhiều cầu vồng từ tinh vực cao cấp đổ về Man Hoang đại lục. Tại nơi sâu nhất Vân Hải tinh vực, tinh vực cấp chín với bảy tu chân tinh xếp hình Bắc Đẩu là căn cứ Phá Thiên Tông. Nữ tu sĩ truyền kỳ Lý Thiến Mai (Toái Niết hậu kỳ, hơn 1200 năm tu đạo) nhận lệnh từ sư tổ — lão già tóc trắng thân thể thối rữa ẩn trong pho tượng — đi tinh vực cấp năm truy tìm kẻ đoạt ngọc giản Tư Mã Mặc. Lão già thở dài gọi Tư Mã sư huynh, cho rằng năm xưa sư tôn đã sai."},{"chuong":1091,"tieuDe":"Nuốt Đan Mà Đạo Lại Mờ Mịt","tomTat":"Vương Lâm ở vườn hoa cấm khu phía nam Quy Nguyên Tông nghiên cứu đan phương Niết Không Đan trên mảnh xương thú, tra điển tịch tìm được ba dược liệu quý hiếm gần tuyệt diệt. Hắn thi triển Sưu Hồn lên nguyên thần Độc Bà Tử, lấy toàn bộ ký ức bao gồm thuật luyện độc Ngũ Độc Môn, lai lịch ngọc giản chứa dấu ấn Tư Mã Mặc — đại đệ tử Phá Thiên Tông đã ly khai 10 vạn 8 ngàn năm trước, và phương pháp luyện thú hồn biến dị. Ngọc giản là lệnh bài nhập môn Phá Thiên Tông, Vương Lâm nhận định sẽ rất hữu dụng. Hắn dùng nhiều loại thú hồn luyện đan, thất bại 3 lần mới tạo thành Ly Hồn Đan cấp 8, đồng thời thử nghiệm thành công phương pháp luyện thú hồn biến dị tại động phủ trên dãy núi Mạc La. Tĩnh tọa 7 ngày rồi lần lượt nuốt đan cấp 5 và cấp 6, tiến vào trạng thái cảm ngộ kỳ dị — hóa thân thành mãnh thú cảm ngộ quy tắc thiên địa, lĩnh ngộ triết lý về đạo: đan dược Vân Hải dùng thú hồn cho tu sĩ cơ hội truy tìm đạo, muốn sâu hơn cần dùng nhân hồn hoặc tồn tại vượt hơn loài thú. Cuối chương, một luồng cầu vồng mang đám tu sĩ tinh vực cấp 6 tiến vào tầng ánh sáng bảo vệ Mạc La đại lục."},{"chuong":1092,"tieuDe":"Kẻ Bị Đánh Sẽ Trúng Thương","tomTat":"Ba tông phái tinh vực cấp sáu — Ngũ Độc Môn (Trừu Hải, Tịnh Niết sơ kỳ), Ma Tùng Đạo (Triệu Vũ) và Đạo Pháp Môn (Phùng Bội Sơn, Tịnh Niết trung kỳ) — phá tầng phòng hộ Mạc La đại lục hạ xuống truy tìm phản đồ Độc Bà Tử. Ba người đến Quy Nguyên Tông, Trừu Hải dùng lam quang quét kiểm tra rồi đánh trọng thương một đệ tử Nguyên Anh. Lữ Yến Phỉ nổi sát khí phản kháng nhưng bị bảy dấu ấn lam của Trừu Hải phá vỡ, Phùng Bội Sơn quát một tiếng chứa thần thông quy tắc thiên địa trấn áp toàn bộ Quy Nguyên Tông. Trừu Hải phát hiện Tôn Vân mang mùi Ngư Tinh Thảo — cỏ độc chỉ mọc ở sào huyệt mãnh thú cấp sáu — và truy vấn, Lữ Yến Phỉ giải thích do sư thúc tổ mang về. Trừu Hải xâm nhập cấm địa khu vườn phía nam, bị Vương Lâm phát ra một câu lạnh lùng rồi xuất chưởng đánh phun máu, áo ngực vỡ nát lộ ra dấu bàn tay đen kịt khắc sâu, khẳng định sức mạnh vượt trội của Vương Lâm trước tu sĩ Tịnh Niết."},{"chuong":1093,"tieuDe":"Tha Tội","tomTat":"Trừu Hải bị Vương Lâm đánh trọng thương bằng một chưởng khi xâm nhập khu vườn phía nam Quy Nguyên Tông, sinh cơ bị rút chuyển cho đệ tử Nguyên Anh bị thương để chữa trị. Vương Lâm bước ra thi triển Ý Cảnh đạo, thiên địa hư ảo, Phùng Bội Sơn nhận ra đây là cảnh giới đạo tùy thân động mà chỉ đại trưởng lão Đạo Pháp Môn mới đạt. Phùng Bội Sơn và Triệu Vũ phải tự vỗ ngực phun máu xin tội, Vương Lâm cho phép tiếp tục tìm kiếm nhưng ra lệnh tìm xong phải rời khỏi Mạc La đại lục. Ba người rời đi, phân tích kết luận Vương Lâm chắc chắn là sư thúc tổ Quy Nguyên Tông chứ không liên quan Độc Bà Tử. Họ nhắc đến Lô Vân Tòng Tử Đạo Tông đang nhắm vào Quy Nguyên Tông vì ân oán, sẽ đá trúng khối sắt. Vương Lâm suy tính nội tâm: trên Man Hoang đại lục vẫn còn manh mối chưa xóa, quyết ưu tiên nâng tu vi, xác định Phong Tiên Giới là sát chiêu chuẩn bị cho Thác Sâm, đang mạo hiểm thử phương pháp luyện thú từ ký ức Độc Bà Tử."},{"chuong":1094,"tieuDe":"Ba Vấn Đề","tomTat":"Lô Vân Tòng dẫn hơn ba mươi đệ tử hạch tâm của Tử Đạo Tông cưỡi hổ thú xuyên sương mù, tiến về Mạc La đại lục để tới Quy Nguyên Tông. Trên đường, hắn phân tích vụ đan phương và ngọc giản, kết luận Độc Bà Tử không đủ khả năng ngăn tự bạo, thoát lục soát và giết Tiền Quý Chung trong thời gian ngắn. Theo hắn, một tu sĩ thần bí thực lực rất cao đã đoạt vật, giết Tiền Quý Chung rồi giá họa cho Độc Bà Tử, khiến các tông phái cấp sáu tự có cớ xóa manh mối. Lô Vân Tòng tán thưởng tâm trí và thủ đoạn của người này, nói muốn kết giao và có dự cảm một ngày sẽ đối mặt. Khi đoàn còn nửa ngày đường tới Mạc La đại lục, Lý Thiến Mai của Phá Thiên Tông xuất hiện trên Linh long lam sắc, tay cầm ống sáo xanh biếc, chặn trước lối đi. Nàng nói muốn hỏi Lô Vân Tòng ba vấn đề, mở đầu bằng câu hỏi cái gì là thiên; Lô Vân Tòng đáp thiên là nhà tù, khiến nàng tiếp tục truy vấn vì sao."},{"chuong":1095,"tieuDe":"Lô Vân Tòng Không Thể Bằng!","tomTat":"Lý Thiến Mai đặt ba câu hỏi cho Lô Vân Tòng về thiên, đạo và nơi hắn đang đi, khiến hắn trả lời sắc bén hai câu đầu nhưng vẫn lộ ra giới hạn ở câu hỏi thứ ba. Nàng đồng hành cùng hắn tới Mạc La đại lục, còn lão già tùy tùng thầm hy vọng hai người kết thành đạo lữ để Tử Đạo Tông dương danh. Trên đường, Lô Vân Tòng phân tích tu sĩ thần bí đã đoạt đan phương và ngọc giản, xem người đó là kẻ quyết đoán, tâm trí sâu và đáng để đánh một trận. Tại dược viện Quy Nguyên Tông, Vương Lâm đang nghiên cứu đan dược cấp tám của Vân Hải tinh vực và nhận ra sơ hở của phương thức mượn thú hồn chứng đạo. Lô Vân Tòng cùng Lý Thiến Mai âm thầm xâm nhập, rồi Lô Vân Tòng dùng ý cảnh dung nhập từng bước chân để tạo uy áp tấn công. Vương Lâm chỉ nói một chữ “Ngồi” đã phá tan toàn bộ ý cảnh ấy, tiếp đó đạo niệm của hắn được đối chiếu qua các giai đoạn Sinh Tử Luân Hồi, Nhân Quả Tuần Hoàn, Nhân Quả Viên Mãn và Chân Giả Ý Cảnh. Chứng kiến Lô Vân Tòng hoàn toàn không thể so sánh, Lý Thiến Mai chuyển sang muốn hỏi Vương Lâm ba câu."},{"chuong":1096,"tieuDe":"Thiên Chỉ Là Lời Bịa Đặt","tomTat":"Sau những biến cố trước đó, Vương Lâm đã trở thành tồn tại khiến tu sĩ Quy Nguyên Tông kính sợ, còn Lô Vân Tòng khi đối diện hắn thì rơi vào thế tiến thoái lưỡng nan vì đạo niệm bị áp chế. Lý Thiến Mai, đệ tử Phá Thiên Tông, tự giới thiệu lai lịch và xin hỏi Vương Lâm ba vấn đề về đạo, đồng thời nói rõ nàng không liên quan chuyện Tử Đạo Tông. Trước câu hỏi cái gì là thiên, Vương Lâm không trả lời ngay mà dùng hai vòng tròn để luận rằng thiên chỉ tồn tại vì người ta tin vào nó, thoát khỏi vòng này lại rơi vào vòng khác, nên thiên chẳng qua chỉ là lời bịa đặt. Lời luận đạo ấy khiến đạo niệm cả đời của Lô Vân Tòng xuất hiện vết nứt, làm hắn tái nhợt khạc máu và không thể phản bác. Với Lý Thiến Mai, đạo luận của Vương Lâm quét sạch mây đen bế tắc trong tâm thần nàng, điều mà nhiều người trước đó chưa làm được. Khi được hỏi tục danh, Vương Lâm xưng là Lữ Tử Hạo và nhận Cực Tài Đan bán thành phẩm cấp mười do Lý Thiến Mai trao để đổi lấy câu trả lời thứ nhất. Ở câu hỏi thứ hai cũng là cái gì là thiên, Vương Lâm nhìn ra đây không còn là cực hạn đạo niệm mà là thiên ý, khiến Lý Thiến Mai kinh ngạc và khiến Lô Vân Tòng hiểu vì sao mình từng không đủ tư cách trả lời tiếp câu thứ ba."},{"chuong":1097,"tieuDe":"Quay Đầu Mỉm Cười","tomTat":"Vương Lâm tiếp tục luận đạo với Lý Thiến Mai và Lô Vân Tòng, dùng mưa sinh ra từ hơi nước vạn vật rồi bị cuốn ngược trở lại mây để diễn giải nhân quả tuần hoàn, vận mệnh và thiên ý. Lô Vân Tòng nghe xong chấn động, từ thế đối địch chuyển sang kính phục, còn Lý Thiến Mai tâm phục và trao cho Vương Lâm ngọc giản ghi phương pháp luyện đan cùng thông tin đan dược bán thành phẩm chứa linh hồn mãnh thú cấp mười. Khi Lý Thiến Mai hỏi câu thứ ba về thiên, Vương Lâm đưa ra đáp án cá, lưới, sông và ngư ông, còn nàng dẫn lời sư tôn rồi cho rằng đạo chỉ là tư tưởng, khiến cả Vương Lâm lẫn Lô Vân Tòng đều có chút tỉnh ngộ. Ba người luận đạo từ ngày sang đêm; bên ngoài, lão già cưỡi mãnh hổ dẫn hơn ba mươi đệ tử hạch tâm xông vào Mạc La đại lục vì lo lắng nhưng bị Lô Vân Tòng quát lui. Sau đó Lô Vân Tòng xin Vương Lâm trả Âm Tiên Phiên, tiết lộ vật này do chủ tông ban xuống và trăm năm sau phải dâng lại, nhưng Vương Lâm từ chối. Lô Vân Tòng chấp nhận cái chết của con trai như tạo hóa, uống rượu rồi cáo từ rời đi. Cuối chương, Lý Thiến Mai thổi sáo, tuyên bố không hỏi ba vấn đề ấy với ai nữa, quay đầu mỉm cười trước khi rời dược viện, còn Vương Lâm mở bừng mắt trong dư âm tiếng sáo và những tiếng đàn trong ký ức."},{"chuong":1098,"tieuDe":"Tinh Vực Cấp Chín Thần Bí Ở Phía Sau","tomTat":"Bồng Lai đại lục được giới thiệu là một tu chân tinh trong tinh vực cấp năm, do Bảo Ngọc Tông nắm một nửa và nổi tiếng với chợ, đấu giá cùng Bồng Lai Loạn Pháp ba mươi năm mở một lần. Vương Lâm cùng Lý Thiến Mai đi tới Bồng Lai, trong đó Vương Lâm đồng ý chuyến đi vì muốn tìm bản đồ tinh cầu, vật cực quý giúp đi lại trong sương mù Vân Hải. Trên đường, Lý Thiến Mai giải thích sự khan hiếm của bản đồ tinh cầu và cách các tông phái cấp cao dùng truyền tống trận đặt ở tinh vực cấp thấp để giảm lệ thuộc vào bản đồ. Khi Vương Lâm hỏi về tinh vực cấp chín, nàng tiết lộ bốn tông phái gồm Thần Tông, Quỷ Tông, Yêu Tông và Phá Thiên Tông. Nàng nói Thần Tông từng là tông phái duy nhất, đã trấn áp cuộc nổi loạn mãnh thú lần thứ nhất rồi phái đệ tử phòng thủ không gian đứt gãy liên quan đến một tinh vực thần bí. Nhóm đệ tử ấy sau nhiều ngàn năm tách thành Yêu Tông, còn Thần Tông đề bạt Quỷ Tông và Phá Thiên Tông để chuẩn bị cho cuộc nổi loạn lần hai. Lý Thiến Mai dặn Vương Lâm giữ kín bí mật, còn Vương Lâm sau khi nghe xong bắt đầu suy tư tinh vực thần bí kia rốt cuộc ở đâu."},{"chuong":1099,"tieuDe":"Ngươi Là Ai?","tomTat":"Lý Thiến Mai kể cho Vương Lâm về bí ẩn tinh vực cấp chín: cứ vài trăm năm, tu sĩ các tông phái lại hình thành đại quân viện trợ Yêu Tông ở tiền tuyến chống mãnh thú từ tinh vực thần bí, và chiến tranh mới sắp nổ ra. Nàng nhờ hắn nếu ngày ấy đến thì tới tiễn biệt, Vương Lâm gật đầu nhận lời rồi nhớ lại cảnh Lữ Yên Phỉ tiễn hắn rời Mạc La đại lục và dặn đừng quên Quy Nguyên Tông. Hôm sau, Vương Lâm cùng Lý Thiến Mai đến Bồng Lai đại lục; nàng đổi tóc xanh thành đen để tránh bị nhận ra, còn hắn bình thản quan sát tu chân tinh đầu tiên nhìn thấy từ khi tới Vân Hải. Hai người vào khu chợ do Bảo Ngọc Tông tổ chức, nơi các tảng đá khổng lồ hình mũi dùi lơ lửng nhờ trận pháp và diễn ra nhiều giao dịch náo nhiệt. Lý Thiến Mai giải thích Vân Hải thiếu tiên ngọc vì Phong tiên giới bị Văn Thú chiếm giữ, đồng thời nói về nguyên tinh, vật phẩm quý giúp tu sĩ Đệ Nhị Bộ hồi phục nguyên lực, tu luyện và tế luyện pháp bảo. Trong lúc Vương Lâm chứng kiến một giao dịch đổi nguyên tinh lấy tiên ngọc, Dương Ngọc xuất hiện cùng hai tùy tùng, nhận ra Lý Thiến Mai và tỏ ra thân mật. Lý Thiến Mai lạnh nhạt cảnh cáo hắn không được gọi tên nàng suồng sã, khiến Dương Ngọc nổi giận rồi quay sang nhìn Vương Lâm, lạnh lùng hỏi hắn là ai."},{"chuong":1100,"tieuDe":"Chuyện Gì?","tomTat":"Vương Lâm bỏ qua Dương Ngọc để đến quầy của Âu Dương Long, thương lượng mua khối nguyên tinh và dùng túi trữ vật chứa tiên ngọc làm tiền đặt cọc. Âu Dương Long nhận giao dịch, hẹn ba ngày sau tìm hắn, đồng thời tự giới thiệu và cảnh báo Dương Ngọc là tam đệ tử chưởng môn Ma Tùng Đạo cấp sáu. Khi nhóm Dương Ngọc tiếp tục dò xét, Vương Lâm ra tay phế hai tu sĩ Tịnh Niết sơ kỳ, một bằng ngón tay hóa kiếm và một bằng ánh mắt song hư thực kèm một chữ Đạo. Sau đó hắn dùng ý cảnh bước chân ngộ từ Lô Vân Tòng để ép Dương Ngọc phun máu, rơi vào ảo giác và phải cầu cứu sư thúc. Sư thúc Dương Ngọc hiện thân, giải ảo cho hai đệ tử, gọi Vương Lâm là Lữ đạo hữu, xin lỗi và mời hắn ngồi đàm phán. Vương Lâm suy luận Ma Tùng Đạo có thể đang thử tu vi mình vì Triệu Vũ hoặc vì sơ hở trên Man Hoang đại lục, còn Lý Thiến Mai chấn động khi nhận ra tâm trí hắn đáng sợ hơn cả tu vi."},{"chuong":1101,"tieuDe":"Khó Hiểu","tomTat":"Vương Lâm dùng thân phận họ Lữ cùng Lý Thiến Mai tới tầng ba một khách điếm trong khu chợ Bồng Lai để gặp hai trưởng lão Ma Tùng Đạo là Đường Lệ Hải và Ngô Thanh. Ma Tùng Đạo mời hắn làm trưởng lão ngoại sự, hứa cung cấp tài liệu luyện đan và vật dụng, đổi lại chỉ cần hắn giữ gìn tôn nghiêm của tông môn, nhưng Vương Lâm chưa nhận lời mà hẹn trả lời trước khi rời Bồng Lai. Sau khi hắn rời đi, một nam tử trung niên bí ẩn từng ẩn thân ở chiếc bàn không người hiện hình, cùng hai trưởng lão đánh giá Vương Lâm cực kỳ nguy hiểm và khuyên Ma Tùng Đạo rút khỏi chuyện đan phương cùng ngọc giản. Vương Lâm tách khỏi Lý Thiến Mai, đi khắp khu chợ ba ngày để mua bản đồ tinh cầu, thu được sáu tấm nhưng vẫn chưa hài lòng, đồng thời nhận ra manh mối trên Man Hoang đại lục đã bị người khác nhìn ra. Đến hoàng hôn ngày thứ ba, đệ tử của Âu Dương Long tới mời hắn vào tòa thành trung tâm, nơi có trường đấu thú và buổi đấu giá tư nhân do sư thúc Âu Dương Long chủ trì. Âu Dương Long nhiệt tình dẫn đường rồi hỏi vì sao Vương Lâm biết thân phận thật của mình, còn Vương Lâm chỉ mỉm cười không đáp."},{"chuong":1102,"tieuDe":"Toái Niết Hội Tụ","tomTat":"Âu Dương Long dẫn Vương Lâm, lúc này dùng thân phận Lăng Tiêu và ngoại hình giống Ngô Thanh, vào phòng đấu giá tư nhân dành cho tu sĩ Toái Niết, đồng thời nhắc rằng nơi này không nên che giấu tướng mạo. Trong phòng, Vương Lâm gặp Thương Tùng Tử, lão giả Toái Niết trung kỳ chủ trì buổi tụ họp, cùng nhiều tu sĩ Toái Niết sơ kỳ khác, trong đó có Ngô Thanh thật. Thương Tùng Tử mở cuộc đặt cược đấu thú; Vương Lâm dựa vào ghi chép của Quy Nguyên Tông chọn mãnh thú Sí Vân và đặt một trăm khối tiên ngọc. Sau đó Thương Tùng Tử đưa ra ba vật phẩm: Huyết Tinh Kiếm được thiếu phụ áo hoa mua, bộ tàn giáp không ai nhận ra lai lịch được tặng cho Vương Lâm, và Hỗn Nguyên Đan được thanh niên văn sĩ mua với giá năm vạn tiên ngọc. Lão già áo đen tay vuốt ưng tiếp tục lấy ra lông Chu Tước, khiến Vương Lâm chấn động trong lòng nhưng vẫn che giấu phản ứng. Cuối chương, lão già này trưng bày linh hồn hung thú cấp mười hai nửa hóa sương, làm Ngô Thanh tiếc rẻ vì nó chưa hoàn toàn hóa sương."},{"chuong":1103,"tieuDe":"Gió Muốn Bùng Lên","tomTat":"Trong buổi tụ hội giao dịch, lão già hắc y gầy khô đưa ra thú hồn mãnh thú cấp mười hai và lông vũ Chu Tước, khiến nhiều tu sĩ chú ý nhưng liên tục từ chối các mức trả giá chưa đủ. Bà lão áo xanh muốn mua thú hồn nhưng thiếu mười vạn tiên ngọc, Vương Lâm liền mua bản đồ tinh cầu của bà để giúp giao dịch hoàn tất. Sau đó lông vũ Chu Tước được đấu giá, Vương Lâm ra tới ba vạn tiên ngọc nhưng Ngô Thanh cố ý nâng giá từng bước để thăm dò tài lực hắn, khiến hắn cười lạnh từ bỏ và giấu sát khí. Buổi giao dịch kết thúc, Thương Tùng Tử xin lỗi thay Ngô Thanh rồi đổi năm ngàn nguyên tinh cho Vương Lâm, đồng thời từ chối bán Hỗn Nguyên Đan vì chỉ còn một hạt. Cả Thương Tùng Tử lẫn Vương Lâm đều có ý đồ riêng: lão cho rằng nguyên tinh không dễ bị mang đi, còn Vương Lâm cần nguyên tinh tẩm bổ Văn thú để chuẩn bị tiến vào Phong Tiên giới. Khi Vương Lâm rời căn lầu, bà lão áo xanh xuất hiện, nói bản đồ trước đó là giả, tặng bản đồ thật và cảnh báo hắn chú ý Ngô Thanh. Vương Lâm rời thành bay về phía tây Bồng Lai đại lục, không lâu sau Ngô Thanh phóng theo truy đuổi, khiến các tu sĩ trong khu chợ chú ý và bà lão áo xanh trong chủ thành chỉ cảm khái đáng tiếc."},{"chuong":1104,"tieuDe":"Ngươi Tới Chậm","tomTat":"Ngô Thanh rời khu chợ Bồng Lai truy sát Vương Lâm, khiến các lão quái đại thần thông đồng loạt dùng thần thức theo dõi; Thương Tùng Tử còn thầm tính lợi dụng mâu thuẫn này để đoạt nguyên tinh, trong khi Đường Lệ Hải nhớ lời cảnh báo không được trêu chọc Vương Lâm nên chỉ than thầm. Vương Lâm chủ động dừng lại trên bình nguyên biên giới đông tây Bồng Lai, quyết định đánh bại đối phương thật dứt khoát để lập uy trước toàn bộ tu sĩ nơi đây và khiến Ma Tùng Đạo không dám báo thù. Ngô Thanh thi triển thần thông ngưng núi rồi dùng Lực bạt thiên tạo vòng xoáy trắng đen che trời, nhưng đều bị Vương Lâm phá tan: một quyền nghiền nát ngọn núi, tiếp đó dùng thần thông ba chỉ học từ Lỗ Phu Tử điều động nguyên lực khắp Bồng Lai, đánh tan vòng xoáy và trọng thương lão. Khi nhận ra Vương Lâm tuyệt đối không phải tu sĩ Tịnh Niết bình thường, Ngô Thanh đã quá muộn; Vương Lâm thi triển Dịch Linh Ấn, dấu chưởng cấp chín giáng xuống khiến thân thể Ngô Thanh nổ tung, nguyên thần tiêu tán, đồng thời Vương Lâm cũng đoạt sạch đồ trong khe trữ vật của lão. Dấu chưởng sau đó vượt khỏi kiểm soát, xuyên phá khu chợ Bồng Lai, làm chủ thành nghiêng lệch rồi lao lên tinh không, hấp thu sương mù và đánh nát Man Hoang đại lục, khiến chính Vương Lâm cũng chấn động trước uy lực của nó. Toàn bộ tu sĩ quan chiến kinh hoàng: Thương Tùng Tử run rẩy, các lão quái nhận ra dấu hiệu Thần Tông, những kẻ từng có ý định ra tay đều âm thầm may mắn vì chưa động thủ, còn tu sĩ trung niên Ma Tùng Đạo vừa chạy tới đã mất sạch ý niệm báo thù. Vương Lâm bình tĩnh phủi bụi đá trên áo, bước đến trước mặt người của Ma Tùng Đạo và lạnh nhạt cho biết hắn đã đến muộn."},{"chuong":1105,"tieuDe":"Đệ Tử Môn Phái Thần Tông","tomTat":"Trương Kỳ của Ma Tùng Đạo ra mặt trước Vương Lâm, tuyên bố Ngô Thanh đã bị trục xuất khỏi tông phái và dâng Cách Hồn Đan cùng bảo vật để cầu hòa. Lý Thiến Mai quan sát từ xa, nhận ra Dịch Lịch Ấn là thần thông hạch tâm của Thần Tông nhưng cũng chú ý một chưởng quái dị của Vương Lâm có thể điều khiển thiên địa nguyên lực. Vương Lâm trở về khách điếm, kiểm tra chiến lợi phẩm và khiến lông vũ Chu Tước dung nhập vào mắt trái, nhận ra cần thêm lông vũ để Chu Tước thức tỉnh lần thứ ba. Đỗ Đức, chủ nhân cũ của lông vũ, đến kết giao và trao ngọc giản về Man Hoang đại lục tinh vực cấp sáu, nơi có mãnh thú hệ hỏa cấp mười một. Hai ngày sau, Thương Tùng Tử thu mua bản đồ tinh cầu trong chợ tặng Vương Lâm, rồi đưa ngọc giản về một nơi bí ẩn và mời hắn hợp tác tiến vào. Vương Lâm nâng thù lao lên hai vạn nguyên tinh, còn Thương Tùng Tử dù nghi ngờ thân phận của hắn vẫn quyết định lợi dụng cơ hội vì đã chuẩn bị cho nơi đó suốt ngàn năm."},{"chuong":1106,"tieuDe":"Cá Quay Về Nước, Quên Đi Chuyện Trên Bờ","tomTat":"Khu chợ trên Bồng Lai đại lục sau khi bị Vương Lâm phá hỏng đã được Bảo Ngọc Tông khôi phục trong hai ngày, rồi mở đấu giá tại quảng trường trung tâm chủ thành. Vương Lâm đến dự trong sự cung kính của các tu sĩ, được Tào trưởng lão đại diện Bảo Ngọc Tông tiếp đón và nhận hai bảo vật hắc quang của hắn để đưa vào đấu giá đổi nguyên tinh. Khi đại trận bia đá trồi lên, hắn ngồi ở hàng Toái Niết cùng các cường giả khác. Lý Thiến Mai đến bên cạnh, báo rằng nàng phải rời Bồng Lai vì vết nứt chỗ Yêu Tôn xuất hiện thêm nhiều mãnh thú, các đệ tử tông phái cấp chín phải đi viện trợ. Trong lúc đấu giá, Vương Lâm lên tiếng lấy bức tranh sóng nước, không ai dám tranh vì sợ uy thế của hắn sau chuyện Ngô Thanh. Hắn tặng bức tranh cho Lý Thiến Mai; nàng nhận, nhờ hắn chuyển lời mời của Phá Thiên Tông nếu tìm được người tông môn đang tìm, rồi bay đi với mái tóc chuyển xanh. Vương Lâm nhìn theo và tự vấn về câu cá quay về nước, liệu có thật sẽ quên chuyện trên bờ hay không."},{"chuong":1107,"tieuDe":"Thần Ma Giáp","tomTat":"Sau khi Lý Thiến Mai rời đi, Vương Lâm không ngoái đầu mà hồi tưởng về những vết thương tình cảm trong đời mình, đặc biệt là Lý Mộ Uyển và Liễu Mi. Lý Thiến Mai để mái tóc trở lại màu lam, dấu hiệu độc nhất tại Vân Hải, qua đó giúp chúng tu sĩ tin hơn vào thân phận đệ tử Thần Tông của Vương Lâm. Buổi đấu giá tiếp tục với ngọn núi đá không hoàn chỉnh của Vương Lâm; vật này được nhận ra có tiên khí, có dấu vết Sưu Hồn bị tổn hại và được trưởng lão đạo môn mua với giá một nghìn nguyên tinh. Sau đó Tào trưởng lão đưa ra Thần Ma Giáp, Vương Lâm mở cấm chế khiến ma khí ngập trời bùng lên, toàn trường nhận ra đây là tứ phẩm Thần Ma Giáp chỉ người Thần Tông mới có. Vương Lâm vì thế nảy sinh hứng thú mạnh với Thần Tông trong Vân Hải tinh vực. Cuộc đấu giá Thần Ma Giáp leo thang giữa nhiều tu sĩ, đặc biệt là Âu Dương Long và thanh niên áo vàng Bí Lạc Tông, giá bị đẩy lên ba vạn nguyên tinh và xung đột giữa hai bên bắt đầu lộ rõ."},{"chuong":1108,"tieuDe":"Tư Cách","tomTat":"Thương Tùng Tử xuất hiện trong cuộc đấu giá bộ giáp, áp đảo thanh niên áo vàng Bí Lạc Tông bằng tài lực và lời uy hiếp, cuối cùng mua được bộ giáp ở mức sáu vạn nguyên tinh. Lão giao cho Vương Lâm một vạn nguyên tinh đặt cọc cùng ngọc giản bản đồ tinh cầu, rồi rời Bồng Lai để tới điểm hẹn bí mật. Trên đường, Vương Lâm gặp Lý Thiến Mai quay lại vì nhớ lời hắn hứa tiễn nàng; nàng nói thú loạn nghiêm trọng, tặng vòng ngọc phòng hộ nhưng bị từ chối, rồi trao bức tranh đã vẽ thêm hai con cá sát cánh. Vương Lâm đáp lễ bằng cây bút bảo vật Tiên giới, còn chiếc vòng ngọc bị ném đi lại tình cờ rơi đúng tuyến đường hắn phải đi nên hắn thu lấy. Tại Man Hoang đại lục, Thương Tùng Tử cùng lão già họ Bàng, bà lão áo xanh và Vân Hồn Tử tập hợp, bàn về việc cần Vương Lâm vì hắn có thể thi triển Dịch Linh Ấn. Vân Hồn Tử đến muộn cùng rất nhiều âm hồn, khinh thường Vương Lâm là tiểu bối Tịnh Niết và lập tức sai âm hồn lao tới thử tư cách của hắn."},{"chuong":1109,"tieuDe":"Quần Ma Tụ Hội","tomTat":"Vương Lâm vừa tới gần nhóm Thương Tùng Tử thì bị Vân Hồn Tử, lão quái Toái Niết trung kỳ dùng hồn làm chủ, tung âm hồn thử tu vi. Vương Lâm đánh trả một quyền, đẩy lui phần lớn âm hồn nhưng cố ý giữ lại thực lực, khiến bản thân lùi năm bước và không để lộ hết bài tẩy. Thương Tùng Tử can thiệp bằng màn phi kiếm kim quang, ngoài mặt bảo vệ khách quý nhưng trong thần niệm lại cùng Vân Hồn Tử bàn cách dò xét và đối phó Vương Lâm. Sau đó Đoan Mộc đồng tử cưỡi trường kiếm lớn tới nơi, nghe Thương Tùng Tử tiết lộ mục tiêu có Hồi đan nhưng bị Giao Long hóa sương cấp mười hai canh giữ. Trần Thiên Quân của Dịch Thú Tông cũng lộ diện, cho thấy mình đã ẩn nấp từ trước, rồi giết đàn mãnh thú đi theo và luyện linh hồn chúng thành đan dược đen nuốt vào. Khi đủ sáu người, Thương Tùng Tử hứa thu hoạch sẽ không khiến mọi người uổng công, riêng Vương Lâm ngoài nguyên tinh còn được chọn thêm bảo vật, rồi dẫn cả nhóm hóa cầu vồng bay sâu vào Man Hoang đại lục."},{"chuong":1110,"tieuDe":"Cao Chót Vót","tomTat":"Thương Tùng Tử dẫn đoàn xuyên qua sương mù tinh không đến chỗ sâu nhất của tinh vực cấp năm, nơi Man Hoang đại lục ẩn trong sương mù. Lão sai Bàng lão giả thanh trừ toàn bộ tu sĩ trên đại lục, rồi kích hoạt Tứ Sơn trận khiến bốn ngọn núi bùng hào quang và bóc lớp đất đá để lộ ký hiệu khổng lồ dưới mặt đất. Vương Lâm quan sát và nhận ra Man Hoang đại lục bất động khác thường, từ đó đoán nơi này không giống các đại lục trôi chậm trong Vân Hải tinh vực. Thương Tùng Tử dùng vài chục vạn tiên ngọc nạp tiên lực vào ký hiệu, khiến cả đại lục chuyển động và lộ ra vết nứt bảy màu bên dưới. Lão kể năm xưa đã phát hiện vết nứt này và kéo đại lục đến che giấu, nay phải dùng cả đại lục đâm vào để cưỡng ép mở rộng lối vào. Khi đại lục va thẳng vào vết nứt, đoàn người lần lượt bay vào, nhưng ở khoảnh khắc cuối chỉ còn Vương Lâm và Vân Hồn Tử, Vân Hồn Tử bất ngờ gọi ra thanh thiết kiếm rỉ sét mang lực lượng kinh thiên động địa để tập kích Vương Lâm."},{"chuong":1111,"tieuDe":"Vân Hồn Tử Đâu Rồi","tomTat":"Trước khi vào vết nứt bảy màu, Vương Lâm âm thầm phân tích quan hệ trong đội ngũ và nhận ra Vân Hồn Tử là trợ lực thân cận của Thương Tùng Tử, còn Đoan Mộc và Trần Thiên Quân chỉ là quan hệ lợi dụng. Hắn quyết định không mạo hiểm giết Vân Hồn Tử mà chỉ cần làm đối phương bị thương và lệch khỏi vị trí truyền tống chung. Ngay lúc Vân Hồn Tử sắp vào vết nứt, Vương Lâm dùng Thiết Kiếm và uy lực Thứ Không Niết Bảo tập kích, rồi thi triển Định Thân Thuật và lực lượng Cổ thần, chém đứt tay phải đối phương và làm vết nứt xiêu vẹo. Khi nhóm người xuất hiện trong thế giới bảy màu, Vương Lâm thấy tất cả đều có mặt trừ Vân Hồn Tử nên biết nước cờ đã thành, dù bản thân phải cố áp chế phản phệ. Thương Tùng Tử và lão giả họ Bàng nghi ngờ, chất vấn Vương Lâm, nhưng hắn lạnh lùng phủ nhận và cảnh cáo ngược lại. Đoan Mộc chen lời cho rằng Vân Hồn Tử có thể tự không muốn đi cùng hoặc bị truyền tới nơi khác, khiến Thương Tùng Tử tạm xuống nước. Cuối chương, Vân Hồn Tử tỉnh lại trong một sơn cốc sâu đầy sương mù, mất tay phải và kinh hoàng trước tiếng gầm cùng mùi máu tanh trong nơi nguy hiểm ấy."},{"chuong":1112,"tieuDe":"Thế Giới Bảy Màu","tomTat":"Sau khi chuyện Vân Hồn Tử bị gác lại, Thương Tùng Tử dẫn đoàn người tiến sâu vào thế giới bảy màu và cảnh báo không được tản thần thức quá xa hay bay quá cao vì ngay vòng ngoài đã có mãnh thú cấp mười hai. Trên đường qua tế đàn, bình nguyên và núi sâu, lão giới thiệu nơi này có mãnh thú hóa sương, nguyên tinh, thi hài cổ nhân và nhiều cấm chế cổ đã hư hỏng nhưng vẫn cực kỳ đáng sợ; Vương Lâm nhận ra uy lực cấm chế còn vượt động phủ Thanh Lâm. Đoàn người tới một con đường hẹp bị sương mù chắn, nơi có hài cốt và viên Hồi đan không hoàn chỉnh tỏa mùi thuốc khiến nguyên thần chấn động, đồng thời liên quan trực tiếp tới Nhật Nguyệt Hồi Đạo của Đoan Mộc. Thương Tùng Tử thừa nhận đã mời Đoan Mộc vì cần Hồi Đại Tự Tại mở đường, còn các bên lần lượt phân chia lợi ích: Trần Thiên Quân muốn hồn phách Giao Long, Đoan Mộc muốn thân thể, Vương Lâm muốn toàn bộ nguyên tinh trong sương mù. Đoan Mộc thi triển dấu ấn nhật nguyệt và Hồi thuật để ảnh hưởng Giao Long hóa sương cấp mười hai trong mười nhịp thở, mở màn trận vây công. Trần Thiên Quân dùng u quang dung nhập thân Giao Long, Thương Tùng Tử hóa mấy vạn phi kiếm, bà lão áo xanh gọi gió tuyết, lão Bàng đánh lôi cầu, còn Vương Lâm áp sát và tung quyền vào thân thể khổng lồ của nó."},{"chuong":1113,"tieuDe":"Đừng Cử Động","tomTat":"Nhóm Vương Lâm dồn toàn lực vây công Giao Long hóa sương cấp mười hai: Đoan Mộc dùng phong ấn nhật nguyệt khống chế, Thương Tùng Tử điều khiển vạn kiếm, lão giả họ Bàng nện lô cầu, còn lão bà áo xanh dùng huyền băng hút sinh cơ của nó. Phong ấn không chịu nổi phản chấn, Đoan Mộc thổ huyết, dấu ấn trên đầu Giao Long tan vỡ khiến nó thoát khỏi kiềm chế và dần ngưng tụ thành thân thể thật. Trong lúc mọi người còn bị cuốn vào việc vây giết, Vương Lâm nhận ra nguyên tinh trong sương mù sắp biến mất nên lập tức lao vào thu lấy hàng ngàn viên. Giao Long sau đó dùng sừng đen hút nguyên lực và ánh sáng bảy màu, phóng lưới điện hắc quang cùng nhiều hư ảnh, chuẩn bị thăng không trong thế giới bảy màu nơi mọi người không thể bay cao. Vương Lâm quyết đoán bộc phát lực lượng Cổ Thần, chụp lấy đuôi Giao Long rồi kéo mạnh xuống, quật thân thể ngàn trượng của nó vào con đường hẹp khiến đầu nó vỡ nát và làm các tu sĩ khác kinh hãi. Sau trận, Trần Thiên Quân thoát ra từ đầu Giao Long sau khi thu linh hồn, lão bà áo xanh hút hắc khí và máu huyết từ thi thể, còn Vương Lâm lấy được một ngọc giản dưới bộ hài cốt và đưa Hồi đan cho Đoan Mộc. Khi cả nhóm nghỉ ngơi xong và chuẩn bị tiếp tục tiến sâu, Vương Lâm đọc ngọc giản, phát hiện bên trong ghi bí mật liên quan đến thế giới bảy màu, nhưng chưa kịp suy xét trọn vẹn thì mọi người đồng loạt cảm nhận dị thường. Thương Tùng Tử lộ vẻ sợ hãi, vội truyền thần niệm cảnh báo tất cả tuyệt đối không được cử động."},{"chuong":1114,"tieuDe":"Dâng Tặng Tu Chân Hành","tomTat":"Trong thế giới bảy màu, đoàn người bị hàn khí áp sát và Thương Tùng Tử lập tức cảnh báo không được tản thần thức. Vương Lâm nhìn thấy một người áo xám thân thể trong suốt đi tới bên thi thể Giao Long, khiến xác này thối rữa thành máu, rồi Đoan Mộc vì khẽ động tâm niệm mà bị đối phương hút mất ý cảnh Nhật Nguyệt Hồi và mang đi. Sau khi hàn khí tan, Thương Tùng Tử gọi người áo xám là Mê Thất Giả, giải thích quy tắc tránh nguy hiểm, nhưng Vương Lâm và Trần Thiên Quân đều nghi ngờ những người từng mất tích trong các lần trước đã biến thành loại tồn tại này. Trần Thiên Quân cho rằng đi theo Thương Tùng Tử là sai lầm nên rút lui theo đường cũ, còn Thương Tùng Tử không cản nhưng nói hắn khó tự quay về. Để giữ Vương Lâm và lão bà áo xanh tiếp tục, Thương Tùng Tử tiết lộ ở ranh giới ngoài trong thế giới bảy màu có động phủ của Tư Mã Mặc, đại đệ tử Phá Thiên Tông am hiểu luyện đan, đồng thời hứa cho Vương Lâm thu nguyên tinh và chọn vật trong động phủ. Vương Lâm biết đối phương vẫn che giấu mục tiêu thật nhưng đồng ý vì nguyên tinh, sau đó Thương Tùng Tử dùng tiên ngọc dụ mãnh thú hóa sương để lão Bàng lấy nguyên tinh, giúp nhóm thu gần hai vạn. Cuối chương, câu trong ngọc giản bên bộ hài cốt về minh chí, tù phong thiên đạo và dâng lên tu chân hành vang lại trong đầu Vương Lâm, khiến hắn lặng lẽ nhìn thế giới trước mặt."},{"chuong":1115,"tieuDe":"Cửu Bộ Phong Tiên Trận","tomTat":"Vương Lâm suy ngẫm câu nói trong ngọc giản và nhận ra Thương Tùng Tử từng nhiều lần tiến vào thế giới bảy màu nên mới nắm được nhiều tin tức, bảo vật và bản đồ. Đoàn người men theo con đường hẹp giữa hai vách núi, tránh mãnh thú hóa sương và cấm chế tàn vỡ, rồi đến dãy núi cuối cùng chắn đường. Vương Lâm quan sát bà lão áo xanh họ Triệu và phát hiện bà cực kỳ tinh thông cấm chế, trong khi từ xa truyền tới dao động thần thông của Trần Thiên Quân thuộc Dịch Thú Tông. Thương Tùng Tử giải thích trên đỉnh núi có bảy hung thú cấp mười hai nên không thể vượt qua, còn ngọc giản bản đồ chỉ ra nơi đường cụt này có cửa xuyên núi. Triệu lão bà dùng thủ ấn cấm chế làm lộ thạch động và tự mình thử trận, nhưng đến bước thứ sáu thì phun máu bị đánh bật ra ngoài. Bà nhận ra đây là thượng cổ kỳ trận Cửu Bộ Phong Tiên Trận, đã mất lực công kích nhưng phong ấn vẫn hoàn thiện và cần tiến đủ mười bước để phá. Thương Tùng Tử mặc Thần Ma Giáp xông vào, đi tới bước thứ chín rồi bị phản lực đánh bật, sau đó lộ vẻ điên cuồng tuyên bố nếu mình không vào được thì không ai được rời khỏi thế giới này. Cuối chương, Vương Lâm bình tĩnh đứng dậy và nói để mình thử trận."},{"chuong":1116,"tieuDe":"Nên Làm Như Thế","tomTat":"Sau khi Thương Tùng Tử không thể vượt qua trận pháp trong núi đá, Vương Lâm chủ động đứng ra phá trận vì nhận ra lão đang che giấu mục tiêu rất quan trọng. Hắn nhờ bà lão áo xanh mở trận, bước vào vách đá rồi âm thầm đưa cấm chế vô hình vào Cửu Bộ Phong Tiên Trận, đồng thời dùng thân thể Cổ Thần chịu áp lực và cố ý diễn thành trọng thương. Qua từng bước, hắn phun máu và run rẩy khiến Thương Tùng Tử, bà lão áo xanh cùng lão giả họ Bàng đều tin rằng hắn bị ép đến cực hạn. Khi bước thứ mười hạ xuống, trận pháp tan vỡ, dãy núi chấn động, mãnh thú trên đỉnh núi bị kinh động, còn Thương Tùng Tử nhân lúc chộp lấy Vương Lâm để dò xét thương thế hắn bằng nguyên lực và thần thức. Bốn người nhanh chóng theo thông đạo mới mở tiến vào vùng sơn cốc bên trong dãy núi, nơi Thương Tùng Tử nói động phủ của Tư Mã Mặc nằm ở phía trước. Họ vào một động phủ cũ chỉ có ba gian thạch thất và nhiều đan dược đã hư hại; Thương Tùng Tử cùng bà lão áo xanh đều nhường vật phẩm nơi đây cho Vương Lâm. Vương Lâm lấy cớ thương thế nặng để ở lại chữa thương, còn Thương Tùng Tử sắp đặt lão giả họ Bàng ở lại bảo hộ hắn, sau đó cùng bà lão áo xanh tiếp tục đi sâu đoạt bảo vật."},{"chuong":1117,"tieuDe":"Thu Hoạch","tomTat":"Thương Tùng Tử xem sự im lặng của Vương Lâm như đồng ý, để lão già họ Bàng ở lại bảo hộ hắn rồi cùng lão bà áo xanh rời động phủ về phía dãy núi. Khi hai người đi xa, lão Bàng lục soát các thạch thất và trở mặt vì tưởng Vương Lâm trọng thương, nhưng lập tức bị Vương Lâm phản sát, thân thể nổ tung, nguyên thần bị Thiết kiếm chém làm hai. Vương Lâm không giết hẳn lão Bàng mà ép mở không gian trữ vật, chặt đứt liên hệ chủ cũ,搜 ký ức rồi thu nguyên thần suy yếu để tránh kinh động Thương Tùng Tử. Từ chiến lợi phẩm, hắn lấy được hơn mười vạn tiên ngọc, năm sáu vạn nguyên tinh, thảo dược, đan phương, hai địa đồ thế giới bảy màu và khẩu quyết rời khỏi nơi đây. Ký ức lão Bàng giúp hắn biết động phủ hiện tại không phải động phủ thật của Tư Mã Mặc, đồng thời nắm thêm tin tức về nơi phong ấn nhiều linh hồn mãnh thú. Hắn cũng thu thanh đoản kiếm có khí tức quen thuộc nhưng bị phong ấn, rồi phá tầng phong ấn thứ tám của chiếc nhẫn chín tầng để kích hoạt năm luồng cầu vồng phòng ngự. Sau cùng, Vương Lâm rời động phủ, lần theo cảm ứng kỳ dị hướng tới dấu vết Tán Ma khôi giáp mà hắn khẳng định thuộc về mình."},{"chuong":1118,"tieuDe":"Đạo Kinh","tomTat":"Vương Lâm lần theo dấu vết qua vùng cỏ xanh không sương mù, tới một sơn cốc trước dãy núi và dùng cấm chế kiểm tra. Hắn phát hiện Mai Hoa Thập Bát Cấm do lão bà áo xanh mới bố trí, đồng thời nhìn ra trong trận còn có dấu vết Sinh Tử Cấm hút sinh cơ cỏ cây. Thay vì phá trận, Vương Lâm thêm Phá Diệt Tâm Cấm của mình vào trận pháp chưa hoàn thành, biến mai phục thành phản bẫy đủ uy hiếp cả lão bà áo xanh lẫn Thương Tùng Tử. Trên đường vượt dãy núi, hắn nhớ lại lời Lý Nguyên về Tứ Đại Cấm Thuật, nguồn gốc từ hư và khả năng dung hợp bốn cấm để cảm ngộ Hư Thật. Sau khi lên đỉnh núi, Vương Lâm nhìn thấy vùng sương mù đen bên trong, cảm nhận được Thương Tùng Tử ở sâu trong đó rồi nhảy xuống truy đuổi. Trong sương mù, Thương Tùng Tử mặc Thần Ma Giáp đi cùng lão bà áo xanh, tính rằng Bàng Đức có thể đã sưu hồn Lữ đạo hữu để lấy Dịch Linh Ấn. Hai người gặp một tượng đá nam tử cao gần trăm trượng có dấu ấn tia chớp trên mi tâm, rồi bị âm thanh và hư ảnh quỷ dị xuyên thấu tâm thần. Thương Tùng Tử nhận ra đó là Minh Chí Giả, giải thích họ có đạo cảnh nhưng không có Đạo Kinh nên chỉ còn chấp niệm đạo hồn truy tìm, đồng thời tiết lộ Đạo Kinh trong thiên địa này nghe nói do máu huyết thiên địa tạo thành."},{"chuong":1119,"tieuDe":"Thương Tùng Tử Quá Nhiều Bảo Vật","tomTat":"Thương Tùng Tử nói rõ với lão bà áo xanh họ Triệu rằng mục tiêu thật của lão không phải linh hồn mãnh thú mà là Đạo Kinh, thứ được liên hệ với nhiều Minh Chí Giả và lời lưu truyền về khai sáng. Hai người tiến sâu trong sương mù nhiều ngày, chịu âm thanh quỷ dị ảnh hưởng tâm thần, rồi phát hiện một ngọn núi nhỏ bị vầng sáng đen bao bọc. Lão bà áo xanh nhận ra đó là phong ấn trong Tuế Nguyệt Cấm, hấp thu quy tắc thời gian và càng tồn tại lâu càng mạnh, nên việc phá cấm cực kỳ khó. Để tăng cơ hội, Thương Tùng Tử lần lượt lấy bốn Phá Cấm Trùy, khối gỗ đen, tinh thạch rực rỡ và cuối cùng là ngọc bội Thứ Không Niết Bảo thật. Lão bà áo xanh dùng thuật cấm chế, hắc khí, máu tươi và pháp quyết điều khiển các bảo vật tự hủy, khiến màn cấm chế hỗn loạn, nứt ra rồi khôi phục. Khi ngọc bội Thứ Không Niết Bảo bị tự hủy, màn cấm mở một lỗ hổng mười trượng khôi phục rất chậm, Thương Tùng Tử và cô gái áo xanh lập tức lao vào. Sau đó Vương Lâm xuất hiện, không vội tiến vào mà bố trí nhiều cấm chế bên ngoài rồi mới xông qua lỗ hổng."},{"chuong":1120,"tieuDe":"Bình Ngọc Dưới Bộ Hài Cốt","tomTat":"Khe nứt trên tấm màn Tuế Nguyệt Cấm đang nhanh chóng khép lại, nên Thương Tùng Tử dẫn cô gái áo xanh họ Triệu gấp rút vào ngọn núi nhỏ bên trong. Lão dùng con lắc màu trắng hình tia chớp mở cửa động phủ phong ấn thú hồn, để nàng vào lấy thú hồn rồi khép cửa đá nhốt lại, còn mình lên đỉnh núi mở cầu vồng bảy màu. Qua vòng xoáy cuối cầu vồng, Thương Tùng Tử tới không gian tấm bia cao vạn trượng, thấy nửa bộ hài cốt màu đen bị đinh bảy màu đóng giữ, trên xương phủ văn tự Đạo Kinh. Lão không dám xem Đạo Kinh vì biết người xem sẽ thành Minh Chí Giả, mà nhắm thẳng tới bình ngọc đặt dưới xương sống trong trận pháp ngục tù. Khi bình ngọc hút bạch khí từ thân lão, lão tung hơn một ngàn nguyên thần bị phong ấn cho bình hấp thu, rồi dùng máu và bốn tiểu kiếm kim quang phá trận để nhấc bình lên. Người phụ nữ trung niên áo xanh họ Triệu hiện thân trong không gian tấm bia, dùng cấm chế ngăn bốn tiểu kiếm nhưng bị kim quang hóa lỏng xuyên qua phòng hộ. Khi Thương Tùng Tử định rời khỏi thế giới này trước khi khe nứt khép lại, bà lão áo xanh họ Triệu lại xuất hiện, khiến lão nhận ra đó không phải phân thân mà là cấm thuật Dương Tụ Âm Quy đã đạt cảnh giới ba đời."},{"chuong":1121,"tieuDe":"Thiên Vận Lại Tái Hiện","tomTat":"Lão bà áo xanh mở màn giao chiến với Thương Tùng Tử bằng lực hút đoạt sinh cơ, khiến lão phải phản công bằng kim quang hóa vạn phi kiếm và thả ra một nguyên anh hình người kỳ dị. Khi Thương Tùng Tử định rời đi qua sóng gợn, một lão phụ nhân áo xanh từ hư vô phục kích, dùng độc làm tay trái lão bị hủy hoại, phá thế công và phong ấn nguyên anh hình người. Thương Tùng Tử tiếp tục dùng bảy thanh trường kiếm và hạt châu Nghịch Hành Giả, còn lão phụ nhân dùng khiên tử quang, dung hợp ba nguyên thần và thi triển Sinh Tử Cấm, khiến ngọn núi nhỏ tan vỡ và Minh Chí Giả ngoài sương mù bị kinh động. Trong dư chấn, tay trái Thương Tùng Tử bị xé rời, bình ngọc văng ra, Vương Lâm lập tức hiện thân với tốc độ Toái Niết hậu kỳ, chụp lấy bình ngọc rồi lao ra khe nứt. Hắn dùng cấm chế làm tấm màn khép nhanh hơn, khiến Thương Tùng Tử bị cản lại, rồi dán hai tấm phù để kéo giãn khoảng cách với lão phụ nhân đang truy sát. Lão phụ nhân hóa hư ảnh bò cạp độc khổng lồ tấn công, bị Vương Lâm xoay người đánh tan phần đuôi. Thương Tùng Tử lại ném hạt châu khiến ánh sáng bảy màu ngưng thành ngón tay khổng lồ, làm Vương Lâm nhận ra đó là Thiên Vận Nhất Chỉ và kết luận nơi này liên quan đến Thiên Vận Tử. Cùng lúc đó, ba luồng Sinh Tử Cấm của lão phụ nhân dung hợp, mang toàn bộ tinh túy lực lượng phóng về phía Vương Lâm."},{"chuong":1122,"tieuDe":"Tam Xoa Kích","tomTat":"Vương Lâm đoạt bình ngọc nhưng phát hiện vật này không thể đưa vào không gian trữ vật, đành cầm trong tay và dùng hai tấm phù tăng tốc bỏ chạy trước Thiên Vận Nhất Chỉ cùng ba luồng Sinh Tử Cấm. Khi thế công áp sát, hắn hóa thân thành Cổ Thần hơn ba trăm trượng, mi tâm hiện năm tinh điểm và tinh điểm thứ sáu mơ hồ, rồi dùng một quyền đánh tan Thiên Vận Nhất Chỉ. Tới dãy núi, Vương Lâm triệu thanh Tam Xoa Kích đen khổng lồ từ khe nứt mặt đất, dùng nó chém đứt Sinh Tử Cấm; ba mũi kích hóa thành Hắc Long thôn phệ cấm khí và để lại ba ký hiệu trên thân kích. Sau khi cảnh cáo Thương Tùng Tử và lão phụ nhân áo xanh rằng nếu còn dây dưa hắn sẽ giết người, Vương Lâm tiếp tục bị truy kích vì Thương Tùng Tử không cam lòng mất bảo vật đã chuẩn bị ngàn năm. Hắn dẫn lão phụ nhân vào sơn cốc có cấm chế, điều khiển ngược vòng xoáy khói đen của bà ta, mở hàng vạn cấm chế dung hợp Sinh Tử Cấm với Phá Diệt Cấm khiến bà ta rơi vào tình cảnh sinh tử. Thương Tùng Tử nhận ra Vương Lâm cũng tinh thông cấm chế, quyết định nhân cơ hội giết họ Lữ đoạt bình ngọc; lão dùng vạn kim quang phi kiếm nhưng bị Tam Xoa Kích đánh bật. Cuối chương, Thương Tùng Tử lấy ra thanh kiếm trong suốt tỏa khí tức Thứ Không Niết Bảo, còn Tam Xoa Kích dung hợp ba ấn ký Sinh Tử Cấm vào Hắc Long, lộ ra thần thông thật sự của nó."},{"chuong":1123,"tieuDe":"Huyết Chiến Với Thương Tùng Tử","tomTat":"Tam Xoa Kích lộ rõ lai lịch là vũ khí do Cổ Thần Đồ Ti luyện chế, ẩn chứa thần thông thôn phệ vạn vật mà Thiên Vận Tử từng không mở được. Vương Lâm nhờ đã thành Cổ Thần chân chính sau Nhất Tổn Nhị Kiếp nên kích hoạt thần thông này, khiến Tam Xoa Kích hóa Hắc Long thôn phệ Sinh Tử Cấm và Tinh Kiếm. Thương Tùng Tử liên tục tung sát chiêu, dùng Tinh Kiếm, kiếm khí, ba hạt châu triệu hồi Nghịch Hành Giả, nguyên anh huyết sắc, Huyết Nguyên Hóa Anh và cây đinh bảy màu để vây giết Vương Lâm. Vương Lâm chống trả bằng Tam Xoa Kích, Hô Phong, Hoán Vũ, Phong Tiên Ấn, hư ảnh Diệt Thần Thương, chưởng ấn, Thiết Kiếm và Dịch Linh Ấn, đồng thời gọi các chiến hồn như Hư Không Tử, Thiên Vận Tử và Ngô Thanh tham chiến. Trận chiến đi đến lưỡng bại câu thương: Vương Lâm bị tia chớp đánh ngực và đinh bảy màu ghim vai, còn Thương Tùng Tử bị mũi Thiết Kiếm gãy xuyên ngực rồi trọng thương bỏ chạy. Vương Lâm thu pháp bảo rời khỏi chiến trường, không để ý lão bà áo xanh còn bị cấm chế bao phủ, nhưng La Bàn khổng lồ trên bầu trời vẫn chậm rãi chuyển động truy theo hắn."},{"chuong":1124,"tieuDe":"Phá La Bàn","tomTat":"Vương Lâm trọng thương sau trận chiến với Thương Tùng Tử, thu gom pháp bảo rồi bỏ chạy nhưng bị La Bàn khổng lồ liên tục truy kích, phóng ký hiệu bảy màu gây thương tích nặng thêm. Hắn quyết phá La Bàn bằng cách dồn toàn bộ lực Cổ Thần còn sót vào Tam Xoa Kích, kích hoạt giáp Chu Tước tạo biển lửa, phóng sấm sét ngưng tụ thành ngọn núi lôi quang, rồi thi triển Cửu Huyền Biến phân chín hợp nhất lao thẳng lên phá nát La Bàn thành bốn năm mảnh, một hình bóng đỏ thẫm thoát ra biến mất. Tiếng nổ vang vọng khắp thế giới bảy màu khiến Trần Thiên Quân, lão phụ nhân áo xanh, các Mê Thất Giả và Minh Chí Giả đều chú ý. Thương Tùng Tử đang chữa thương trên ký hiệu tia chớp, hồi tưởng tổn thất nặng nề gồm ba hạt châu, Thủy Tinh Kiếm và đặc biệt chiếc đinh bảy màu, khi cảm ứng La Bàn bị cắt đứt thì lần đầu chính thức sinh ra sợ hãi đối với Vương Lâm. Lão tiết lộ trung tâm thật sự của thế giới bảy màu là một sơn cốc sương mù sâu hơn. Vương Lâm miễn cưỡng vào động phủ bỏ hoang, thả Ngân Y Nữ Thi và Hứa Lập Quốc ra hộ pháp rồi hôn mê bất tỉnh, trong khi Ngân Y Nữ Thi lộ ánh mắt dịu dàng mê man còn Hứa Lập Quốc đứng canh tự khen phong lưu."},{"chuong":1125,"tieuDe":"Đinh Bảy Màu","tomTat":"Sau khi Vương Lâm hôn mê, Ngân Y Nữ Thi dựa trí nhớ mơ hồ đặt Sinh Tử Cấm lên cổng động phủ bảo vệ, phương pháp thành thạo hơn cả lão bà áo xanh. Vương Lâm tỉnh dậy phát hiện cây đinh bảy màu từ trận chiến trước găm chặt vào xương vai phải và nguyên thần, liên tục phá xương cốt, hấp thu sinh cơ. Hắn tổng kết tình hình các đối thủ: Thương Tùng Tử chỉ nguyên thần thoát, lão bà áo xanh bị nhốt trận pháp có Phá Diệt Tâm Cấm, Vân Hồn Tử bị truyền tống lung tung, Trần Thiên Quân bỏ đi sớm. Vương Lâm cố rút đinh nhưng thất bại, hào quang bảy màu lan sang toàn bộ khung xương phải kèm luồng tức giận lạ xâm nhập tâm thần. Hắn thu được bình ngọc chứa chất lỏng đen — mục tiêu thật sự của Thương Tùng Tử, suy đoán liên quan tu vi. Sau đó thu Hứa Lập Quốc và Ngân Y Nữ Thi vào trữ vật, rời động phủ ra dãy núi mãnh thú hóa sương. Hắn dùng thân xác Cổ Thần chịu đòn trực diện từ ba mãnh thú ưng cấp 12, chuyển toàn bộ lực chấn động lên xương vai phải, cuối cùng ép được cây đinh bảy màu bùng nổ văng ra dù thân thể trọng thương gần tan vỡ."},{"chuong":1126,"tieuDe":"Bí Mật Của Tư Mã Đặc","tomTat":"Vương Lâm chụp được cây đinh bảy màu rồi lợi dụng lực phản chấn trốn vào đường ngầm trong núi, ba mãnh thú hình ưng không dám đuổi theo. Hắn dưỡng thương hai ngày bằng lực Cổ Thần và đan dược, khôi phục hoàn toàn đến đỉnh phong. Sau đó kiểm kê chiến lợi phẩm: thu cây đinh bảy màu làm đòn sát thủ, đeo chiếc nhẫn chín tầng phòng thân, tế luyện nguyên anh huyết sắc hình người của Thương Tùng Tử xóa ký hiệu, xác nhận Thủy Tinh Kiếm phẩm cấp Thứ Không Niết Bảo. Nhận định cuộc chiến với Thương Tùng Tử thực chất là so sánh ai đoạt nhiều bảo vật hơn, Vương Lâm dựa ký ức Bàng Đức Tài lên đường tìm động phủ Tư Mã Mặc. Xuyên qua vùng sơn cốc dày đặc đã bị lục sạch, hắn đến sơn cốc mục tiêu và phá hai tầng cấm chế: tầng hư ảo bằng trình độ cấm chế, tầng Tuế Nguyệt Cấm hai vạn năm bằng ngọc giản di vật Tư Mã Mặc lấy từ Man Hoang đại lục. Bên trong sơn cốc trăm trượng có chín hang động cửa đá đóng kín, bộ hài cốt xương lộ sáng bảy màu ngồi tựa vách đá trước ba ngọc giản. Vương Lâm đọc ngọc giản thứ nhất biết Tư Mã Mặc thuộc tinh vực Vân Hải, từng cùng sư thúc và đồng môn theo yêu cầu của một người bí ẩn khám phá khe nứt không gian bảy màu, phát hiện tồn tại đáng sợ và bí mật khổng lồ khiến cả Vân Hải, La Thiên, Triệu Hà, Côn Nhai đều khiếp sợ. Tai họa ập xuống khiến bọn họ bị mắc kẹt cả đời."},{"chuong":1127,"tieuDe":"Chưởng Tôn","tomTat":"Vương Lâm đọc ba khối ngọc giản từ hài cốt Tư Mã Đặc, biết toàn bộ quá trình vài trăm năm đồng môn Phá Thiên Tông trong thế giới bảy màu. Ngọc giản thứ nhất ghi: ba năm đầu Nhị sư đệ và Lão Tam thành Mê Thất Giả, Tư Mã Đặc tìm được ngọc giản Tuế Nguyệt Cấm, sư thúc bị âm thanh kêu gọi đi vào vị trí sâu nhất, Minh Chí Giả tấn công mang đi nhiều đồng môn, cuối cùng bố trí đại cấm chế bảo hộ sơn cốc, Cửu sư đệ hy sinh gia cố trận pháp. Ngọc giản thứ hai ghi: sau trăm năm chỉ còn ba người, Tứ sư thúc trở thành Nghịch Hành Giả đầu tiên, Tư Mã Đặc đi cứu đồng môn từ đám Mê Thất Giả và Minh Chí Giả. Ngọc giản thứ ba ghi: Tư Mã Đặc phát hiện hạt châu phong ấn Nghịch Hành Giả, vào cứu Tứ sư thúc lần thứ tư bị cây đinh bảy màu đâm gây ý niệm điên cuồng, đuổi Thập Lục sư đệ đi kèm lệnh bài và đan phương, phát hiện hạt châu do người tế luyện rồi tự tạo ra nhiều thạch châu, cuối cùng ý thức kéo dài nhìn thấy cường giả tên Chưởng Tôn. Vương Lâm kinh hoàng liên hệ: Chưởng Tôn cùng thời đại Thanh Lâm, lão già Ngoại giới gọi mình là Phong Tôn khi thấy hạt châu Thiên Nghịch, cây đinh bảy màu gây điên cuồng giống Thanh Thủy. Mở động phủ thứ nhất tìm thấy mười hạt châu, đảo thần thức phát hiện chữ Thiên Nghịch."},{"chuong":1128,"tieuDe":"Đan Dược","tomTat":"Vương Lâm nhận ra hạt châu tìm thấy là bản mô phỏng Thiên Nghịch do người xưa tế luyện nhằm tạo Tiên Nghịch, suy đoán kẻ chế tạo có lẽ cũng là Chưởng Tôn. Hắn thu hơn mười mấy hạt châu phong ấn thần thông vào trữ vật và nghi vấn thân phận Thương Tùng Tử vì thần thông cuối lão giống hệt hai người Ngoại giới năm xưa. Khám phá ba động phủ tiếp theo: động phủ thứ hai chứa lò luyện đan khổng lồ cùng lượng dược liệu đồ sộ, động phủ thứ ba có trận pháp bảo vệ ba bình đan dược di vật Tư Mã Mặc. Vương Lâm lập trận pháp hình thoi chuyển hướng khí tức hủy diệt, chộp được cả ba bình: đan cấp mười một, Vụ Hồn Đan cấp mười hai, và đan cấp mười ba có tiếng gầm vượt xa mãnh thú cấp mười hai khiến hắn tái mặt đóng nút. Vì bỏ thân Cổ Thần chỉ còn Tịnh Niết sơ kỳ, hắn bắt đầu luyện hóa lại đan cấp mười một trong lò. Ở nơi rất sâu trong thế giới bảy màu, tế đàn phủ sương lóe hào quang xuất hiện nhóm ba người y phục khác tu sĩ Vân Hải, mi tâm mang ký hiệu tia chớp, trăng lưỡi liềm và ngọn lửa, bàn về khe nứt không gian."},{"chuong":1129,"tieuDe":"Nghe Đạo","tomTat":"Nguyên thần Thương Tùng Tử hấp thu sáng bảy màu và tia chớp từ tượng đá, tái tạo thân thể hoàn chỉnh với da phát sáng bảy màu và ký hiệu tia chớp trên mi tâm, tuyên bố đã tiến lên một bước và thề báo thù. Lão dùng hạt châu phun máu tươi triệu hồi Nghịch Hành Giả để truy tìm Vương Lâm, biết được hắn đang ở động phủ Tư Mã Đặc rồi phóng tới. Tại động phủ, Vương Lâm bố trí cấm chế rồi thả Văn Thú ra cho thôn phệ thú hồn và hấp thu nguyên lực hồi phục, đồng thời tự luyện đan dược từ thú hồn suốt hai ngày. Hắn uống ba bình đan dược, dùng minh ngộ thiên địa của thú hồn làm đối chứng để chứng minh thật-giả đạo niệm bản thân, ngộ ra thật và giả không cần phải tách biệt — đây là thay đổi lần thứ hai của đạo niệm. Đạo niệm bùng ra bao phủ hơn phân nửa thế giới bảy màu, tạo vòng xoáy hút ý cảnh khiến Thương Tùng Tử đến cách sơn cốc ngàn trượng hai ngày mà không thể tiến lên. Mê Thất Giả, Minh Chí Giả và mãnh thú hóa sương cấp mười hai đều tụ về bên ngoài sơn cốc để cảm ngộ đạo của Vương Lâm. Trong lúc chứng ngộ, tâm thần Vương Lâm xuất hiện âm thanh bí ẩn nói về Minh Chí tù phong thiên đạo và dâng tặng Tu Chân Hành."},{"chuong":1130,"tieuDe":"Đạo Tán","tomTat":"Vương Lâm minh ngộ sâu, hồi cố toàn bộ hành trình đạo niệm từ Sinh Tử Luân Hồi qua Nhân Quả Tuần Hoàn đến Chân Giả Chi Biến. Hắn uống sạch đan dược cấp mười một và tiếp tục dùng đan dược cấp tám đến mười từ Bồng Lai đại lục bay qua khe nứt không gian, đan dược đến gần tự tan vỡ để thú hồn bị cuốn vào vòng xoáy đạo niệm đối chiếu. Đạo niệm hỗn tạp tản ra bao phủ toàn thế giới bảy màu, khiến Mê Thất Giả dần có thần thái, Minh Chí Giả có cảm giác thực chất, mãnh thú mất hung tính, đạo tâm Thương Tùng Tử suy sụp. Tâm thần Vương Lâm thoát thể quét khắp sơn cốc, xuyên qua Tuế Nguyệt Cấm phát hiện hai ngọn núi bí mật: ngọn thứ nhất chứa bia đá không chữ giống pháp khí, ngọn thứ hai có kho thú hồn phong ấn cấp bảy đến cấp mười ba, thiếu nữ giống lão bà áo xanh đang thổ nạp, và không gian ẩn giấu chứa nửa bộ hài cốt bị hai cây đinh bảy màu ghim với chữ viết dâng tặng Tu Chân Hành. Tâm thần Vương Lâm lần đầu xuyên sương mù vào vùng sâu thế giới bảy màu, phóng qua ba thanh niên ba tộc gây chấn động dữ dội, người trăng lưỡi liềm nghi nhận ra hắn, người ngọn lửa đề nghị liên thủ mở phong ấn đối phó."},{"chuong":1131,"tieuDe":"Thủ Hộ","tomTat":"Tâm thần Vương Lâm thăm dò ngọn núi bí ẩn cao nhất trong thế giới bảy màu, nơi sương mù không dám tới gần, bị lão già tóc trắng tu vi Toái Niết hậu kỳ phóng thần thức tấn công. Vương Lâm triệu hồi toàn bộ đạo niệm đã vứt bỏ trong thế giới bảy màu tạo vòng xoáy phòng thủ, khiến lão già ngừng tay cảnh cáo rồi lui về. Quay về thân thể, Vương Lâm ngưng tụ đạo niệm thành khối tinh thạch đen có uy lực phá đạo tâm tu sĩ Toái Niết, đồng thời nhận ra nhờ kinh văn trên nửa bộ hài cốt mà ý cảnh sắp đạt Tịch Niết trung kỳ. Thương Tùng Tử phẫn nộ thừa nhận thất bại, tiết lộ Bàng Đức Tài không biết cách rời đi thật sự, quyết định rời khỏi bằng con đường riêng rồi phá hủy vết nứt bảy màu phong bế mọi người vĩnh viễn. Vương Lâm truy sát Thương Tùng Tử để lấy đáp án về chất lỏng trong bình ngọc và phương pháp rời đi, triệu hồi Cổ Thần Đại Đỉnh thi triển thần thông Đổi vị hoán đổi vị trí hai người, áp sát tung chưởng tấn công."},{"chuong":1132,"tieuDe":"Loại Đạo","tomTat":"Vương Lâm tái chiến Thương Tùng Tử, triệu hư ảnh Cổ Thần phá sấm sét rồi dùng nguyên thần Thái Cổ Lôi Long hấp thu toàn bộ sấm sét đối phương. Lần đầu tiên sử dụng cây đinh bảy màu xuyên ngực Thương Tùng Tử, khiến lão thân xác nổ sương máu, nguyên thần bị ghim, phát cuồng chết hóa hạt huyết châu. Vương Lâm sưu hồn trích ký ức, đoạt sạch trữ vật, chụp huyết châu — Nghịch Thiên Châu trong nguyên thần tự phát phản ứng thu hồi cây đinh, lần đầu lộ mối liên hệ bí ẩn giữa hai pháp bảo. Trần Thiên Quân (Dịch Thú Tông) chứng kiến trận chiến, kinh sợ cầu xin Vương Lâm mang rời thế giới bảy màu, đổi lại thu nguyên tinh từ mãnh thú hóa sương. Vương Lâm đồng ý, đưa ngọc giản truyền âm rồi trở về động phủ bố trí trận pháp xung kích Tịnh Niết trung kỳ. Trong cung điện cấm địa Thái Cổ tinh vực, ngọc giản Thương Tùng Tử vỡ tan rồi thời gian nghịch chuyển tái ngưng tụ đổi tên thành Vương Lâm, giọng nói bí ẩn thì thào về việc cần linh hồn Vương Lâm để thành đạo. Trên ngọn núi sâu thế giới bảy màu, lão già tóc trắng ngẩng đầu nhìn trời rồi lặng lẽ gật đầu đáp lại tín hiệu."},{"chuong":1133,"tieuDe":"Đạo Tủy","tomTat":"Trong động phủ Tư Mã Đặc ở sơn cốc thế giới bảy màu, Vương Lâm hấp thu toàn bộ nguyên lực thiên địa, đột phá thành công Tịnh Niết trung kỳ, tự đánh giá nếu đạt đại viên mãn kết hợp thân thể Cổ Thần thì lão quái Toái Niết hậu kỳ cũng không phải đối thủ. Hắn lấy bình ngọc cướp từ Thương Tùng Tử, nhờ ký ức đoạt được mà giải mã bản chất chất lỏng bên trong là đạo tủy — được tạo bằng cách dùng Mê Thất giả thôn đạo, Minh Chí giả nuôi đạo, dung nhập vào bia đá, dùng kinh văn hài cốt chuyển hóa ép đạo ra hóa thành huyết dịch; uống vào sẽ đắc đạo tâm chủ nhân nhưng ngủ say vô thời hạn. Vương Lâm khám phá động phủ thứ tư đến thứ tám: động phủ thứ tư trống rỗng; động phủ thứ năm có cấm chế Tuế Nguyệt Cấm, chứa bốn Mê Thất giả như xác không hồn; động phủ thứ sáu chứa ba Minh Chí giả chỉ còn nguyên thần; động phủ thứ bảy chứa lão già tóc hoa râm bị phong ấn dày đặc, phát điên cuồng khi thấy Vương Lâm — hắn nghi là Nghịch Hành Giả. Tất cả đều là đồng môn Tư Mã Đặc bị đưa về phong ấn cố cho thức tỉnh nhưng thất bại. Động phủ thứ tám chứa nửa bộ hài cốt phần dưới có kinh văn đen và lực hút tâm thần khổng bố. Không cam lòng bỏ đi, Vương Lâm tự phong tỏa tâm thần, rút Thủy Tinh Kiếm truyền tâm thần lên, tiến đến bên hài cốt đặt tay lên vết nứt đùi phải dung nhập tâm thần cảm ngộ — khoảnh khắc thần thức đụng hài cốt, trong đầu nổ đùng lên một tiếng."},{"chuong":1134,"tieuDe":"Thiên Đạo Kế","tomTat":"Vương Lâm chạm vào nửa bộ hài cốt trong động phủ thứ tám, tâm thần bị cuốn vào ảo cảnh chứng kiến Chiến Tinh Dã — lão tổ Chiến gia La Thiên — thi triển chữ chiến kim sắc chống lại thần thông bảy màu nhưng bị kẻ tự xưng bản tôn chỉ một chiêu phong ấn giết chết. Kẻ đó tiết lộ mưu kế Thiên Đạo Kế: năm xưa tặng Chiến Tự Thiếp cho Chiến Tinh Dã tu luyện đạt Không Linh Chi, rồi giết lấy chiến hồn làm dẫn tìm xương cốt sư phụ hắn là Chiến Lão Quỷ Không Kiếp, bức ra đạo tủy hai sư đồ. Thủy Tinh Kiếm tự phản ứng cắt đứt liên kết cứu Vương Lâm tỉnh lại. Vương Lâm suy luận kẻ có lực lượng thái sơ dùng thần thông cùng loại Tàn Dạ có thể là Chưởng Tôn, và lão già trong Chiến Tự Thiếp chính là Chiến Lão Quỷ. Hắn lấy ba bức Chiến Tự Thiếp ra, kim quang từ hài cốt bùng phát nhập vào khiến ba bức dung hợp thành một, xuất hiện chữ chiến kim sắc hư ảo, thu Chiến Tự Thiếp hoàn chỉnh. Rời động phủ, để lại nguyên tinh cho hài cốt Tư Mã Mặc, qua trận pháp phong ấn lão bà áo xanh đã bị mở rồi tiến vào sương mù đến tượng đá khổng lồ, từ ký ức Thương Tùng Tử hiểu được công pháp Bách Thế Huyết Nguyên Hóa Anh triệu hồi Đệ Thất Linh Phong giới tạo chín nguyên anh tự ngưng tụ thần thông."},{"chuong":1135,"tieuDe":"Ngạo","tomTat":"Vương Lâm ngồi trên đỉnh đầu tượng đá, nhớ lại con đường Thương Tùng Tử đã chọn — quy thuận thờ phụng tượng đá để nhận truyền thừa sấm sét — và quyết định đi con đường ngược lại: dùng sự kiêu ngạo của kẻ nghịch tu và tôn nghiêm Cổ Thần để bắt buộc sấm sét khuất phục. Hắn triệu hồi nguyên thần Thái Cổ Lôi Long thôn phệ con rồng sấm sét do tượng đá phóng ra, kết hợp cánh tay Cổ Thần huyễn hóa bóp nát rồng sấm sét, khiến lôi cầu trăm trượng cuối cùng quy thuận và phóng vào nguyên thần Lôi Long khiến nó trở nên khổng lồ. Chương tiết lộ tượng đá là tổ tiên Thiểm Lôi tộc — tộc dân thái cổ do sấm sét nghịch thiên biến thành, ký hiệu tia chớp trên mi tâm chứa minh ngộ cả đời, lôi cầu chứa Lôi linh là ý niệm khi chết. Vương Lâm dung hợp lôi quang thành ký hiệu tia chớp đánh vào mi tâm tượng đá, hai mắt tượng đá bùng hào quang mở ra ảo cảnh tinh không: trận pháp lớn như tinh vực giam cầm Luyện Khí Sĩ và Tiên nhân, bên ngoài có đám người kỳ dị không phải tu sĩ đứng chế giễu, bên trong có chín luồng hào quang tàn sát gồm Khai Thiên Phủ và tia chớp."},{"chuong":1136,"tieuDe":"Ta Là Tu Sĩ, Vì Sao Phải Ngại Một Trận Chiến?","tomTat":"Mắt tượng đá hiện ra cảnh cuối cùng: người Ngoại giới đứng ngoài trận pháp khinh miệt nhìn Tiên nhân bên trong trước khi chết, Tiên nhân phát lời thề diệt Ngoại giới. Tượng đá tan vỡ, tia chớp từ mắt tượng đá xuyên thời không rơi vào mắt phải Vương Lâm khiến hắn chấn động, máu nóng thiêu đốt. Ba thanh niên Ngoại giới bàn bạc trong sương mù, quyết định mở phong ấn dùng lực lượng đỉnh phong để giết Vương Lâm, rồi lần theo dấu vết sấm sét phóng đi. Vương Lâm phóng đến ngọn núi Tuế Nguyệt Cấm, dùng Phá Diệt Cấm định vị vết nứt cũ, dùng Thủy Tinh Kiếm và Tam Xoa Kích xé toạc cấm chế tiến vào không gian kỳ dị, tìm thấy tấm bia đá khổng lồ và nửa bộ hài cốt bị đinh bảy màu ghim chặt. Hắn lấy chữ Chiến hư ảo từ không gian trữ vật, kim quang từ hài cốt phóng ra dung hợp vào chữ Chiến rồi nhập mi tâm. Di ngôn Chiến Tinh Dã vang lên: thà tan vỡ đạo niệm chứ không cấu kết Ngoại giới, yêu cầu giết sạch dân Ngoại giới tế linh hồn. Ý cảnh Vương Lâm bắt đầu dung nhập chiến ý. Ba thanh niên Ngoại giới tìm đến, mở phong ấn biến hóa thân thể tập kích, nhưng Vương Lâm xoay người lại với nụ cười chế giễu, nói: ta là tu sĩ, sao phải ngại một trận chiến."},{"chuong":1137,"tieuDe":"Lôi?","tomTat":"Vương Lâm đối mặt ba tu sĩ Ngoại giới trong thế giới bảy màu, bùng chiến ý và hồi tưởng trận chiến năm xưa bên cạnh Vọng Nguyệt trong hư vô. Hắn dùng tốc độ tuyệt đối và kiếm chỉ liên tiếp đánh nát ngực người Thiểm Lôi Tộc, rồi bùng Chân Giả ý cảnh đạp tan trái tim đối thủ, sau đó dùng ký hiệu tia chớp mắt phải thu hồi tư cách điều khiển sấm sét của Thiểm Lôi Tộc khiến sấm sét quay lại thiêu hủy chính kẻ đó. Tiếp theo hắn phóng biển lửa từ mắt trái bao phủ mấy trăm trượng, khiến ngọn lửa do chính người Hỏa Tước Tộc điều khiển phản bội thiêu đốt chủ nhân thành tro bụi. Người Hỏa Tước Tộc trước khi chết triệu hoán Tộc linh — con chim lửa đen khổng lồ, nhưng Chu Tước thật (trắng) xuất hiện từ thân Vương Lâm khinh thường rồi thôn phệ hoàn toàn Tộc linh, sau đó có dấu hiệu thức tỉnh lần thứ ba. Người thứ ba mang ký hiệu trăng lưỡi liềm hoảng sợ muốn bỏ chạy, bị Vương Lâm gọi là nô tộc và nói tộc hắn ngày xưa dám tự xưng thiên đạo trước mặt ta, khiến kẻ kia hồn bay phách tán."},{"chuong":1138,"tieuDe":"Quy Ước Thái Cổ","tomTat":"Vương Lâm giao chiến với thanh niên Nguyệt Phệ tộc mang ký hiệu trăng lưỡi liềm, dùng lực lượng Cổ Thần áp đảo hoàn toàn thuật Lực Phản Nguyệt của đối phương. Trong tuyệt vọng, thanh niên Nguyệt Phệ sử dụng cấm thuật Nguyệt Cấm thần nộ — quỳ gối triệu hồi hư ảnh Cổ Thần vài trăm trượng mượn thần hồn lực. Vương Lâm kích hoạt Cổ Thần Tinh Điểm, dùng ngôn ngữ Cổ Thần với tư cách vương tộc ra lệnh linh hồn Cổ Thần tiêu tán, chính thức xóa bỏ quy ước Thái Cổ che chở Nguyệt Phệ tộc. Sau đó đá gãy xương cốt thanh niên Nguyệt Phệ, ghim hắn vào hai cây đinh bảy màu trên bộ hài cốt dưới bia đá, sưu hồn lấy ký ức rồi để hắn chết dần trong tra tấn. Ngọn lửa Chu Tước trên người Vương Lâm đạt độ cao mới, liên tục kéo lên Chu Tước Đệ Tam Biến. Tại Thái Cổ tinh vực, sấm sét vĩnh hằng trong địa phương Thiểm Điện tộc tiêu tán nhất thời gây kinh hoàng, ba pho tượng Nhạn Tước của Hỏa Tước tộc tan vỡ ứng truyền thuyết sắp quay về, và Nguyệt Phệ tộc phát sinh biến đổi kinh thiên khiến toàn tộc chấn động."},{"chuong":1139,"tieuDe":"Có Thể Sao?","tomTat":"Hệ quả việc Vương Lâm xóa bỏ quy ước Thái Cổ lan đến cấm địa Nguyệt Phệ tộc — chín pho tượng Cổ Thần khổng lồ dùng để cưỡng chế hấp thu lực lượng Cổ Thần đồng loạt nứt vỡ sụp đổ, lão già tang thương mặc nguyệt bào phóng đến nhận ra nguyên nhân và kinh hoàng. Thanh niên Nguyệt Phệ tộc bị Vương Lâm tiêu diệt hoàn toàn, thân hóa nước máu chỉ còn hai khúc xương trên đinh bảy màu. Chu Tước thức tỉnh lần thứ ba trong Vương Lâm — Chu Tước bạch sắc lao vào mắt trái, ngọn lửa chuyển sang trắng, người ba lần thức tỉnh là linh hồn ngọn lửa thiên địa có quyền hiệu lệnh tất cả lửa. Biển lửa trắng uy lực hủy thiên diệt địa bùng ra: Thần Ma Giáp hóa lỏng bị hấp thu vào thân, ngọn núi trong cấm chế tan vỡ, mọi thú hồn dưới cấp mười hai bị thiêu hoặc đạo niệm dung nhập lửa, tấm màn Tuế Nguyệt cấm sụp đổ hoàn toàn. Lão già tóc trắng ở vị trí sâu nhất thế giới bảy màu mở mắt sợ hãi rồi nhận lệnh hóa cầu vồng phóng về phía Vương Lâm. Trong cung điện bay bổng giữa tinh không Thái Cổ Tinh Thần, hai nhân vật bí ẩn quan sát ngọn lửa — chủ nhân ngón tay héo rũ đưa tay vào nến lửa thể hiện tự tin tuyệt đối, đáp lời chất vấn rằng không sợ lửa thiêu tay."},{"chuong":1140,"tieuDe":"Chu Tước Lam Sắc","tomTat":"Vương Lâm trải qua Chu Tước thức tỉnh lần thứ ba tại thế giới bảy màu. Thân thể Cổ Thần nứt nẻ do khí nóng bùng phát từ bên trong, ngưng tụ nhanh hơn giải phóng, nguy cơ bị thiêu chết. Hắn quyết định nghịch thiên: phong tỏa thất khiếu và toàn thân, giữ trọn ngọn lửa bên trong thay vì phát tiết ra ngoài. Ngọn lửa đạt đỉnh phong nổ tung, chuyển từ bạch sắc sang lam sắc với uy lực kinh thiên — có thể đốt cháy nguyên thần và thân thể tu sĩ Toái Niết, thiêu chết mãnh thú hệ hỏa viên mãn. Biển lửa lam sắc quét khắp thế giới bảy màu, phá hủy mọi trận pháp cấm chế, xua tan sương mù dãy núi hình vòng cung lần đầu tiên sau rất nhiều năm. Chu Tước lam sắc ra đời, Vương Lâm bước ra khỏi lửa hoàn thành dục hỏa trọng sinh. Lão già tóc trắng đang phóng đến nơi Vương Lâm bị lửa lam chặn lại, kinh hoàng. Trần Thiên Quân đang thu hoạch nguyên tinh mãnh thú hóa sương thì bị biển lửa quét qua, sống sót và cảm nhận khí tức Vương Lâm. Cùng lúc tại Tứ Thánh tồn trong Liên Minh tinh vực, toàn bộ tộc nhân Chu Tước Thánh Tông đồng loạt mất kiểm soát ngọn lửa trong cơ thể — hiện tượng cộng hưởng chưa từng có."},{"chuong":1141,"tieuDe":"Thanh Long Thánh Hoàng","tomTat":"Thanh Long Thánh Hoàng bế quan một tháng trong mật thất đại điện Thanh Long, bị tám sợi xích sắt khoá chặt và bốn thanh Thái Cổ Tứ Thánh Khí trấn áp. Thân lão xuất hiện khối thịt quái dị di chuyển dưới da gây đau đớn cực độ, trên đầu hiện hình Thanh Long suy yếu mọc vật huyết sắc. Lão tạm chiến thắng cơn phát tác rồi cảm ứng được Chu Tước Thánh Hoàng đã dục hoả trọng sinh, thức tỉnh Chu Tước lần thứ ba — tộc nhân đầu tiên kể từ thượng cổ. Lão xuất quan, hạ lệnh triệu tập toàn bộ tộc nhân Tứ Thánh Tông thu phục Côn Hư tinh vực — tất cả tu sĩ hoặc quy hàng hoặc chết. Tại thế giới bảy màu, Vương Lâm bước ra từ lửa lam sắc, xác nhận Hoả, Lôi, Chiến đều đã thành Chân Giả ý cảnh, chỉ thiếu cơ hội dung hợp. Vương Lâm tấn công lão già tóc trắng, dùng Chu Tước lam sắc tạo biển lửa vạn trượng phá vỡ la bàn và kiếm khí Nghịch Hành Giả. Lão già tóc trắng dùng hiệu lệnh thủ hộ triệu tập hơn mười Nghịch Hành Giả đồng loạt tấn công Vương Lâm, tự tin pháp bảo do Tôn giả ban không thể bị lửa phá."},{"chuong":1142,"tieuDe":"Phong Diệt Tộc","tomTat":"Vương Lâm đối đầu lão già tóc trắng Toái Niết hậu kỳ, vứt bỏ Sinh Tử Ý Cảnh và dung hợp cảm ngộ lửa thay đạo cảnh, kích hoạt trạng thái Chu Tước thức tỉnh lần ba — Chu Tước lam sắc dung nhập mi tâm, ngoài thân hiện bộ giáp Chu Tước lam sắc. Hắn hiệu lệnh toàn bộ lửa lam trong thế giới bảy màu quét sạch thần thông và chín khúc xương thú của lão già. Lão già trong tình thế nguy cấp bộc lộ thân phận mang một phần huyết mạch Phong Diệt tộc, thi triển Phong Thần thuật phong ấn đồ đằng ngọn lửa trên mi tâm Vương Lâm khiến biển lửa tiêu tán, đổi lại sinh cơ hao tổn không thể khôi phục. Vương Lâm bình tĩnh chuyển sang kích hoạt ký hiệu Thiểm Lôi tộc triệu tập sấm sét tạo địa ngục sấm sét. Lão già kinh hãi vì Vương Lâm đồng thời sở hữu lực lượng Hỏa Tước tộc lẫn Thiểm Lôi tộc, nhận định đây là mầm họa cho bộ tộc thái cổ. Lão già tiết lộ từng đầu nhập Thần Tông học Dịch Linh Ấn và thi triển bàn tay khổng lồ, Vương Lâm nhận ra và cũng đáp trả bằng Dịch Linh Ấn — hai bàn tay khổng lồ đồng thời xuất hiện khiến mặt đất nứt vỡ, phóng thẳng vào nhau."},{"chuong":1143,"tieuDe":"Đạo Thuật","tomTat":"Dịch Linh Ấn giả của Vương Lâm và bản thật của lão già tóc trắng va chạm, lực hủy diệt xé toạc thế giới bảy màu thành hai nửa, cả hai bên đều bị thương. Lão già tóc trắng lập tức thi triển Phong Thần thuật lần hai phong ấn ký hiệu Thiểm Lôi trên mi tâm Vương Lâm, sinh cơ tiêu tán nghiêm trọng, thân thể gầy như xác khô. Vương Lâm bất đắc dĩ kích hoạt Chiến Ý cảnh truyền thừa từ Chiến Tinh Dã, mi tâm hiện chữ chiến kim quang, hóa thân chiến thần dùng thuần thể thuật cận chiến áp đảo lão già. Trần Thiên Quân kinh hãi thề không mạo hiểm vào nơi có bảo vật, lão bà áo xanh oán niệm tan biến thay bằng kinh sợ, Vân Hồn Tử thoát vây khốn khi sương mù co rút. Lão già tóc trắng dốc toàn lực triệu hồi đạo hồn từ toàn bộ Mê Thất giả, Minh Chí giả và mãnh thú, tất cả tan vỡ thành tro. Lão thi triển cấm thuật Tán Đạo của Phong Diệt tộc — đạo thuật sánh ngang Cổ Thần, Cổ Ma, Cổ Yêu — bao phủ hào quang vàng lên Vương Lâm, có thể xóa sạch đạo niệm khiến Tiên cũng sa phàm, nhưng đánh đổi toàn bộ tuổi thọ chỉ duy trì được ba hơi thở."},{"chuong":1144,"tieuDe":"Thiết Trụ","tomTat":"Lão già tóc trắng (Phong Diệt tộc) thi triển đạo thuật cảm ngộ từ đạo cảnh, dùng hào quang vàng xuyên qua Chiến Ý Cảnh của Vương Lâm để xâm nhập ký ức linh hồn nhằm xóa bỏ bản nguyên. Sinh cơ cả đời lão tiêu tán trong ba hơi thở. Vương Lâm bị cuốn vào ảo cảnh, thế giới bảy màu biến thành sơn thôn thanh bình, hắn hóa thành thiếu niên chất phác tên Thiết Trụ đang đọc sách thánh hiền, coi cuộc đời tu tiên hơn nghìn năm chỉ là giấc mộng. Trong ảo cảnh, hắn gặp lại phụ thân, mẫu thân, Tứ Thúc đến báo tin Hằng Nhạc Phái tuyển đệ tử — tái hiện chính xác ký ức thưở đầu. Khi nghe nhắc Hằng Nhạc Phái, ký ức ập về tuần tự: khảo nghiệm thất bại, rơi vực nhặt Nghịch Thiên Châu kèm tiếng thét Thiên Nghịch, bị Đằng Lệ truy đuổi, thề diệt Đằng gia tóc bạc trắng một đêm, lĩnh ngộ lực lượng Cực. Xuyên suốt ảo cảnh, bên tai Vương Lâm vang giọng nói bí ẩn cực kỳ kinh hoàng khi nhận ra cả Thiên Nghịch lẫn Cực đều ở trên cùng một người. Tiếng kinh hoàng vang vọng khiến bầu trời tan vỡ, mặt đất sụp đổ, ảo cảnh tan biến và thế giới quay về hào quang bảy màu."},{"chuong":1145,"tieuDe":"Hương Vị Tuyệt Vời","tomTat":"Vương Lâm tỉnh khỏi Đạo thuật ép nhớ ký ức đau thương của lão già tóc trắng, ảo cảnh thiên địa tan vỡ lộ ra thế giới bảy màu thực sự. Hắn dùng chỉ kiếm phá nát thân xác lão già (tu sĩ Toái Niết hậu kỳ), truy kích nguyên thần bỏ chạy. Trong cơn phẫn nộ, Vương Lâm cưỡng chế phá tan phong ấn Phong Thiên thuật trên cả hai mắt — giải phóng lửa lam và sấm sét, ngưng tụ thành cột lôi hỏa tiêu diệt hoàn toàn lão già dù lão liên tục kêu cứu Tôn giả. Trần Thiên Quân kinh hoàng thán phục, lão phụ nhân áo xanh hạ quyết tâm làm hòa, còn Vân Hồn Tử lại quyết định lợi dụng lúc Vương Lâm trọng thương để liều mạng tấn công. Sau khi giết lão già, chữ Chiến trong cơ thể Vương Lâm kích động trước thứ tồn tại trong ngọn núi sâu nhất thế giới bảy màu, hắn chậm rãi tiến tới cửa động đỉnh núi. Tại đại điện Thái Cổ Tinh Thần, giọng tang thương gọi lão già tóc trắng là Phong Diệt tộc giả mạo, nhận xét Vương Lâm sức lửa đã đến mức nhưng chưa nung nấu hồn phách nên chưa hợp đạo, coi chờ đợi sau khi loại đạo là hương vị tuyệt vời nhất thế gian."},{"chuong":1146,"tieuDe":"Những Cây Hoa Bảy Màu","tomTat":"Vương Lâm bước vào cửa động trong thế giới bảy màu, toàn bộ hào quang bảy màu bị hút vào cơ thể hắn, cảm giác điên cuồng giống Thanh Thủy năm xưa chiếm lĩnh tâm thần, hắn rơi vào Sát Ngục mất hoàn toàn ý thức chỉ còn ý niệm giết chóc. Thế giới bảy màu chìm trong bóng tối. Giọng nói tang thương từ vòng xoáy gọi đó là lửa giận — ngọn lửa tuyệt vời nhất trong thiên địa — yêu cầu Vương Lâm dùng lửa giận nung nấu hồn phách loại bỏ đạo. Linh hồn và nguyên thần Vương Lâm hóa hồng quang thoát khỏi thân xác, phóng vào cửa động đầy nham thạch nóng chảy, khóa sắt treo hài cốt và ngọc giản phong ấn đạo niệm — tất cả tan vỡ khi hắn đi qua. Xuyên qua nham thạch tiến vào vùng tinh không khổng lồ chứa đại trận lớn bằng Liên Minh tinh vực, trung tâm có bảy cây hoa bảy màu được nuôi từ thượng cổ bằng hệ thống Loại Đạo — đại trận bao quanh Phong giới hấp thu đạo niệm tu sĩ chết. Linh hồn Vương Lâm bị hút vào cây hoa đỏ máu, hoàn toàn tiêu tán cùng hài cốt bên trong hóa thành chất lỏng đỏ. Trải qua chín mươi tám năm, Đạo quả đỏ máu ngưng tụ hoàn thành — cây hoa đầu tiên kết quả. Giọng nói tang thương tiết lộ năm xưa được Chưởng Tôn khuyên không đối mặt Không Kiếp, tình nguyện nuôi bảy cây hoa chờ Thiên Đạo Kế hoàn thành, và xem ra đã không còn xa nữa."},{"chuong":1147,"tieuDe":"Thức Tỉnh","tomTat":"99 năm trôi qua kể từ khi Vương Lâm tiến vào thế giới bảy màu. Tứ Thánh Tông quét sạch tông phái còn lại của Liên Minh Tu Chân, cưỡng ép Thi Âm Tông phục tùng rồi cùng khai chiến chống đại quân La Thiên. Thanh Long Thánh Hoàng đơn phương đánh bại tông chủ Đệ Nhất Vương của Thi Âm Tông. Thác Sâm thức tỉnh, phá trận pháp bay ra khỏi Chu Tước Tinh, giết hơn vạn tu sĩ La Thiên rồi lần lượt đánh Thanh Long Thánh Hoàng trọng thương, phá tan tinh vực Tứ Thánh Tông, dập tắt ngọn lửa bất diệt Chu Tước Thánh Tông, phá hủy thánh địa Côn Hư. Mộc Băng Mi bị Thác Sâm đánh tan thân, dùng bí thuật Côn Hư chạy đến Man Hoang đại lục. Thanh Nông xuất hiện thuyết phục Thác Sâm không phá phong ấn Vũ Tiên giới, Thác Sâm mang Luyện Khí Sĩ thượng cổ rời đi. Ở Vân Hải tinh vực, Lữ Yên Phi lo lắng chờ Vương Lâm về dự đại hội chủ tông, Lô Vân Tòng dẫn Tử Đạo Tông phát triển mạnh, Lý Thiến Mai trăm năm chiến đấu tại Yêu Tông. Trong thế giới bảy màu, hạt châu Tiên Nghịch hình thành trong Đạo quả cây bảy màu, Vương Lâm thức tỉnh."},{"chuong":1148,"tieuDe":"Trận Pháp Phong Giới","tomTat":"Thác Sâm thức tỉnh trên tinh cầu hoang tại La Thiên tinh vực, mi tâm lộ tám tinh điểm (bốn sáng, bốn đen kịt chưa hoàn chỉnh). Hắn dùng thần niệm quét khắp Vũ giới, Lôi giới, Thiểm giới đều không tìm thấy khí tức Vương Lâm, tiếng gầm kinh thiên gây đại họa khắp La Thiên — mãnh thú nổ tung, tu sĩ chết hoặc trọng thương, tinh cầu tan vỡ. Thác Sâm xuyên qua Vân Hải tinh vực bằng vòng xoáy khổng lồ, quét thần niệm thổi bay sương mù và giao phong với vài cường giả cấp chín. Hắn biết Vương Lâm chưa chết vì không cảm nhận ký ức truyền thừa tiêu tán, suy luận hắn chỉ có thể đang ở Thái Cổ Tinh Thần. Phá nứt tinh không Vân Hải, Thác Sâm đến vùng hư vô ngoài Tứ Đại giới và tìm thấy Phong Giới đại trận — trận pháp khổng lồ phong tỏa ngăn cách Ngoại Giới và Thái Cổ Tinh Thần. Hắn xuất quyền hai lần: lần một bị phản lực đánh bật lui, lần hai trận run rẩy nhưng không vỡ. Trận pháp kích hoạt Trận linh phản kích — ngưng tụ trường thương trắng bùng sét đánh trúng hắn rồi tạo lưới điện khóa chặt thân, tiếp đó ngưng tụ đoản kiếm lam mang kiếm khí và khí tức âm hàn phóng tới. Người chủ trận ở Thái Cổ Tinh Thần cảm ứng kinh hoàng lóe người tiến đến nhưng chưa kịp tới."},{"chuong":1149,"tieuDe":"Bát Linh Tái Hiện","tomTat":"Thác Sâm đối đầu trận pháp Phong giới Nội giới, triệu Diệt Thần Mâu và Loan đao chiến đấu với các khí linh lần lượt kích hoạt từ Ngũ Linh đến Bát Linh. Lục Linh là xe bắn đá khổng lồ phóng hỏa cầu lửa không màu, buộc hắn rút lui lần đầu. Thất Linh là nha bổng hắc khí hấp thu tâm thần, khiến hắn khạc máu lần đầu. Bát Linh lộ diện là cây búa khổng lồ mang Phụ Tổ Vương Khí — vũ khí Cổ Thần cấp Phụ Tổ Vương, khiến Thác Sâm kinh hoàng vì không thể tin vũ khí tầm này lại thành linh khí trận pháp. Thác Sâm phóng ba tinh điểm chứa khí tức bản nguyên tu sĩ Đệ Tam Bộ hóa lưu tinh, dung nhập bản thân xông trận, rồi thi triển Mặc Lưu Phân Thần Thuật (thuật Đồ Ti chưa hoàn thành) tạo sương mù đen khiến búa do dự. Hắn cho nổ tung lưu tinh tạo khe nứt đầu tiên trên trận pháp từ xưa chưa ai phá được, xông ra ngoài thành công nhưng mất một trong ba tinh điểm. Cảm nhận khí tức Vương Lâm ở Thái Cổ Tinh Thần, Thác Sâm tuyên bố sẽ tìm thôn phệ Vương Lâm."},{"chuong":1150,"tieuDe":"Chủ Nhân Của Thiên Nghịch","tomTat":"Trong tinh vực trận pháp nơi trồng bảy cây hoa bảy màu, cây hoa đỏ thẫm đang kết Đạo quả với hạt châu Thiên Nghịch bên trong. Thiên Nghịch bùng ra ngọn lửa lam, sấm sét và Chiến Ý Cảnh, rồi Chân Giả Đạo huyễn hóa thành thái cực hấp thu tất cả tạo vòng xoáy quanh Thiên Nghịch. Vương Lâm trong trạng thái ý thức mơ hồ hấp thu toàn bộ đạo niệm về hỏa đạo, lôi đạo, chiến đạo từ vô số người tu qua các thời đại. Sáu yếu tố lôi, hỏa, chiến, thật giả, sinh tử, nhân quả dung hợp tạo thành quy tắc mới — đạo riêng của Vương Lâm. Vương Lâm đột phá liên tục từ Tịnh Niết trung kỳ lên hậu kỳ rồi đại viên mãn, tiếp cận rất gần Toái Niết. Vương Lâm tuyên bố mình là chủ nhân chứ không phải nô lệ của Thiên Nghịch, lần đầu tiên hai bên phối hợp cướp đoạt lực lượng thiên địa. Lão già hắc bào canh giữ khu vực phát hiện Đạo quả khô héo, lao tới nhưng bị Thiên Nghịch cản ngoài mười trượng, bất lực nhìn cây hoa đỏ bị hấp thu sạch. Thiên Nghịch bùng sáng vạn trượng, một cánh cửa hư ảo khổng lồ khép kín tỏa khí tức tang thương xuất hiện trong tinh vực."},{"chuong":1151,"tieuDe":"Thân Phận Chủ Nhân Của Phong Giới","tomTat":"Thiên Nghịch hóa cửa lớn mở ra bên trong Phong Giới, phát khí tức chấn kinh thiên địa khiến cường giả thái cổ run rẩy sợ hãi, trận pháp xuất hiện trận linh cuối cùng dưới dạng ngọc bội. Lão già áo đen (phân thân bước thứ ba) lao tới nhưng bị ánh sáng thiêu đốt, nhận ra Vương Lâm là chủ nhân thứ hai của Phong Giới, liều tấn công nhưng bị cánh tay khổng lồ từ Thiên Nghịch tóm diệt. Nhiều nơi cảm ứng khí tức: đồng tử tóc hoa râm trong Thần Tông mở mắt, Thanh Lâm ở Vũ Tiên Giới gọi Sư tôn, lão già hóa đá ở Phong Tiên Giới mở mắt rồi nhắm lại, nữ tử và thanh niên trong Phong Giới cảm nhận khí tức quen thuộc. Nguyên thần Vương Lâm được Thiên Nghịch cuốn phá khai tinh vực, trở về thân xác tại Thất Thải Giới sau trăm năm ngủ say, đột phá từ Tịnh Niết hậu kỳ lên Tịnh Niết đại viên mãn. Lửa và thiểm điện từ hai mắt hóa dấu ấn dung hợp thành quy tắc mới chứa chữ Chiến, rơi vào mi tâm hợp nhất với đạo thật giả thành tinh điểm giống Cổ Thần Chi Tinh. Vương Lâm chủ động phong ấn tu vi Toái Niết vì chưa hoàn toàn hiểu quy tắc mới, giữ ở Tịnh Niết đại viên mãn, quyết định tới Phong Tiên Giới bắt Văn Thú rồi xông vào Thần Tông. Trong Thái Cổ Tinh Thần, Thác Sâm tức giận không cảm ứng được Vương Lâm, lao tới tinh vực có người Thái Cổ cư trú để trút giận."},{"chuong":1152,"tieuDe":"Sự Kính Sợ Của Vân Hồn Tử","tomTat":"Vương Lâm tỉnh dậy sau chín mươi chín năm ngủ say trong Thất Thải Giới, bước ra khỏi ngọn núi khi khe sáng trên đỉnh đã biến mất và màn đêm bao trùm trở lại. Phát hiện Vân Hồn Tử ẩn trong sơn cốc gần đó, Vương Lâm dùng uy áp cường đại gồm ngọn lửa lam, lôi đình, chiến ý trấn áp Vân Hồn Tử khiến hắn đau đớn kêu thảm. Vương Lâm phóng ấn ký thao túng sinh tử vào mi tâm Vân Hồn Tử, thu hắn làm nô bộc, Vân Hồn Tử quỳ xưng chủ nhân. Sau khi biết mình đã ngủ 99 năm, Vương Lâm bay tới sơn cốc Tư Mã Mặc, thấy Văn Thú bị quả trứng bao bọc cực kỳ suy yếu do thiếu nguyên tinh chưa lột xác xong, đau lòng đổ hết nguyên tinh ra cho Văn Thú hấp thụ. Vương Lâm cảnh giác rằng Thác Sâm chắc đã thoát ra ngoài. Sai Vân Hồn Tử đi mời Trần Thiên Quân — người đã cô độc gần 100 năm trong động phủ. Trần Thiên Quân tới gặp, kích động gọi Lữ huynh, giao túi trữ vật chứa nguyên tinh, được Vương Lâm hứa sẽ đưa rời khỏi Thất Thải Giới."},{"chuong":1153,"tieuDe":"Kinh Biến","tomTat":"Vương Lâm dùng lượng nguyên tinh khổng lồ nuôi Văn Thú hoàn thành lột xác sau trăm năm, khí tức đạt ngang Tịnh Niết, thu lại coi là đòn sát thủ bí mật. Sau khi thu dọn toàn bộ vật phẩm động phủ, Vương Lâm dùng một quyền phá Tuế Nguyệt cấm chế trên động phủ thứ sáu và thứ bảy, đoạt ngọc giản ghi chép một trong tứ đại cấm chế, ghi nhớ rồi hủy ngọc giản để độc chiếm. Khám phá động phủ thứ chín — nơi thần bí nhất — phát hiện bộ xương thú hình hươu cắm đoản kiếm trong sương mù bảy màu vĩnh hằng. Hồn phách Thiên Vận Tử trong Phong Tiên Ấn lần đầu tự phát vùng vẫy khi gần sương bảy màu; Vương Lâm dung hợp hồn phách, dẫn toàn bộ sương mù vào cho hồn phách hấp thụ, trong quá trình đó thấy ảo ảnh Thiên Vận Tử thật sự có xác thịt — không chỉ là hồn phách phân thân. Rút đoản kiếm phong ấn (giống thanh kiếm trước kia) khiến bộ xương hóa tro. Dẫn đoàn rời Thất Thải Giới, nhưng tại biên giới bị tồn tại thần bí trong cơn lốc xoáy khổng lồ chặn lại — đòi trả đạo quả, mở màn kinh biến cuối chương."},{"chuong":1154,"tieuDe":"Lòng Bàn Tay","tomTat":"Kẻ bị phong ấn trong cơn lốc xoáy phát lời thách thức — chịu được một chưởng thì cho cơ hội trưởng thành. Uy áp kinh khiếp đè xuống khiến Trần Thiên Quân phun máu, Vân Hồn Tử tái mặt, lão phụ nhân áo xanh phải hiện hư ảnh phòng ngự, riêng Vương Lâm đứng vững nhờ quy tắc ý cảnh vờn quanh thân. Vương Lâm tung quyền triệu trăm vạn lôi đình, hô hào ba người cùng chiến đấu, rồi dùng Tam Xoa Kích cùng sức Cổ Thần phá mở lỗ hổng trong cơn lốc xoáy. Trần Thiên Quân không chịu nổi lực hút, thân xác tan rã, nguyên thần bị chia đôi — Vương Lâm giằng co giật lại một nửa, phần kia bị cơn lốc nuốt mất. Vân Hồn Tử mất toàn bộ âm hồn và pháp bảo cây trùy đen, lão phụ nhân áo xanh tự bạo hai phân thân để thoát ra, cả hai bị thương nặng. Sau khi xuyên qua, năm ngọn núi mọc thẳng lên — lộ ra toàn bộ Thất Thải giới chính là lòng bàn tay khổng lồ đang nắm lại. Vương Lâm mi tâm hiện sáu tinh điểm Cổ Thần cùng một quy tắc chi tinh do ý cảnh hóa thành trông như thất tinh Cổ Thần, cầm Tam Xoa Kích lao xuống đối đầu bàn tay."},{"chuong":1155,"tieuDe":"Ngón Tay Vỡ","tomTat":"Toàn bộ Thất Thải giới hóa thành bàn tay khổng lồ, năm ngón tay từ năm hướng ép vào lòng bàn tay nhằm bóp nát Vương Lâm. Vương Lâm quyết chiến thay vì bỏ chạy, thi triển tổng lực: triệu hồi bảy con hắc long vượt cực hạn nhờ quy tắc chi tinh, thi triển Hoán Vũ biến hóa mới (mưa rơi, đóng băng rồi nổ băng), mở Phong Tiên Ấn phóng chiến hồn tự bạo (trừ Thiên Vận Tử duy nhất không xuất hiện), thi triển Sơn Băng hiện năm ngọn núi lửa, giải phóng toàn bộ Sát Lục Khí ngưng tụ thành Sát Lục Kiếm. Tổng lực tấn công phá vỡ nửa đầu ngón tay út nhưng Vương Lâm phun máu, chiếc nhẫn chín tầng phong ấn của Bàng Đức vỡ nát hoàn toàn. Vân Hồn Tử nhờ Vương Lâm che phía trước nhưng vẫn kinh mạch đứt, xương cốt vỡ, toàn thân đầy máu. Lão phụ nhân áo xanh may mắn thoát lực nổ ngón tay út nhưng bị ngón tay trỏ từ phía sau truy kích, quay đầu đã muộn. Nửa ngón tay út đang điên cuồng hấp thu sức mạnh thiên địa ngưng tụ trở lại. Vương Lâm lao tới ngón tay trỏ, cho nổ Thủy Tinh Kiếm bậc Không Niết khiến ngón trỏ dừng lại, rồi lập tức rút chiếc búa xanh bậc Không Niết thứ hai từ túi trữ vật Thương Tùng Tử."},{"chuong":1156,"tieuDe":"Ngươi Là Chưởng Tôn","tomTat":"Vương Lâm liều mạng phá phong ấn hai pháp bảo Không Niết (chiếc búa và Thủy Tinh Kiếm) giải phóng sức hủy diệt tấn công ngón trỏ bàn tay ngoại giới, lực xung kích khiến thân thể Vân Hồn Tử tan vỡ chỉ còn nguyên thần gần tử vong bị Vương Lâm thu lấy. Cổ Thần đại đỉnh được triệu ra thực thể va chạm trực diện ngón trỏ, sụp đổ vỡ vụn phá hủy hoàn toàn ngón trỏ, nhưng ngón trỏ lập tức tự khôi phục với tốc độ cực nhanh. Ba ngón còn lại đồng loạt tấn công, Vương Lâm ném Tam Xoa Kích cản ngón vô danh rồi lao thẳng đến ngón giữa. Kích hoạt quy tắc chi tinh, toàn thân bùng cháy lửa lam kết hợp lôi đình, dung hợp sức mạnh đạo quả phong ấn và chiến ý cảnh hình thành quy tắc mới chỉ thuộc về duy nhất Vương Lâm, phá hủy hoàn toàn ngón giữa. Trọng thương cực nặng nhưng vẫn lao đến đối mặt ngón vô danh. Người thần bí chủ nhân bàn tay lần đầu động dung, tuyên bố nếu Vương Lâm sống sót sẽ không giết, và tự xưng là Lam Mộng Đạo Tôn của Thái Cổ Tinh Thần Lam Ti Tộc, ngoại giới chưởng tôn."},{"chuong":1157,"tieuDe":"Phúc Hữu Trăm Năm Trước","tomTat":"Vương Lâm bị bàn tay Lam Mộng Đạo Tôn dồn vào tuyệt cảnh trong Thất Thải giới, ba ngón tay đã phá trước đó không ngừng hồi phục. Lần đầu tiên kể từ khi tự xưng Cổ Thần, hắn buộc phải dùng toái tinh — phá vỡ tinh điểm thứ sáu trên mi tâm, nhất thời đạt sức mạnh thất tinh vương tộc Cổ Thần, thân thể vọt lên hơn hai ngàn trượng, phá nát ngón vô danh nhưng nhanh chóng suy yếu. Đối mặt ngón cái chí mạng, Vương Lâm tuyệt vọng trối trăng nhắc tới những người thân thiết rồi lấy vòng tay màu lam đeo lên tay trái. Lam quang tỏa ra khiến Lam Mộng Đạo Tôn nhận ra phúc hữu của con gái Nguyệt nhi đã đầu thai, lập tức buông tha. Vương Lâm dùng ấn quyết ký ức Thương Tùng Tử mở khe không gian thoát về Vân Hải tinh. Cảnh chuyển tới Thái Cổ Tinh Thần, hé lộ Lam Mộng Đạo Tôn là một trong Thái Cổ Ngũ Tôn thuộc bộ tộc Lam Ti, con gái Nguyệt nhi đã đầu thai, vòng tay lam chứa phúc hữu truyền thừa từ vợ Vân Mộng. Lam Mộng đánh giá Vương Lâm là người mạnh nhất trong đám tiểu bối, thề bảo hộ người mang phúc hữu, đồng thời hé lộ chín vùng trời Thất Thải giới vốn do Phong Giới Chí Tôn mở ra rồi bị Thái Cổ đoạt, Chưởng Tôn từng lẻn vào bị trọng thương."},{"chuong":1158,"tieuDe":"Lão Phu Lưu Kim Bưu!","tomTat":"Vân Hải tinh vực sau một trăm năm yên lặng, đại hội so tài ngàn năm một lần giữa các phân tông trong bát giai tông phái sắp diễn ra. Năm bát giai tông phái gồm Vô Cực Tông, Ảnh Phong Tông, Hồng Hồ Tông, Ứng Thiên Tông và Tịch Hồn Đạo. Phân tông thua cuộc sẽ bị giải tán, đệ tử lưu tán. Tịch Hồn Đạo đã thắng liên tục chín trận, sắp đạt tư cách cửu giai. Tại Thiên Cương Tông — phân tông nhỏ yếu ngũ giai thuộc Ứng Thiên Tông — ba lão Chúc Duẫn Minh, La Tòng Cương, Chu Thần lo lắng vì biết sẽ thua. Bất ngờ một ngọc giản chứa khí tức Toái Niết phá tan hộ sơn đại trận, tên lừa đảo kỳ cựu Lưu Kim Bưu tự xưng danh, kể vanh vách tiểu sử ba lão rồi tống tiền sáu vạn nguyên tinh, hứa giúp giải mối nguy giải tán nếu nộp tiền. Cùng lúc đó ở nơi sâu nhất ngũ giai tinh vực, Vương Lâm vọt ra từ đại lục hoang dã, sắc mặt tái nhợt phun máu, vòng ngọc cổ tay chuyển từ lam sang xanh, khe nứt bảy màu đã tắt. Hắn tuyên bố trở về và sẽ hành hạ Lưu Kim Bưu."},{"chuong":1159,"tieuDe":"Phong Tiên Giới","tomTat":"Vương Lâm trở về bát giai tinh vực Vân Hải sau trăm năm trong Thất Thải giới, ngồi trên đại lục hoang dã hồi tưởng toàn bộ trải nghiệm và tổng kết được mất. Hắn tự xác nhận tu vi đã tiến nửa bước vào Toái Niết. Tổn thất đáng kể gồm Thủy Tinh Kiếm bị nát, chiến phủ và Cổ Thần đại đỉnh tan tành, đệ lục tinh Cổ Thần vỡ nát, nhưng thu hoạch vượt xa. Hắn lục soát ký ức hai nguyên thần ấn ký ngọn lửa và tia chớp rồi hút vào chữa thương, biết thêm về Thái Cổ Tinh Thần và Thái Cổ ngũ tôn. Xử lý ba nguyên thần: đáp ứng đưa Trần Thiên Quân về Dịch Thú Tông, lục soát thiên linh lão phụ nhân áo xanh lấy Sinh Tử Cấm rồi thả, thu Vân Hồn Tử vào khe trữ vật. Phát hiện Thiên Nghịch châu phỏng chế hoạt động khi dung hợp chiến hồn Thiên Vận Tử, có thể triệu hoán thần thông Nghịch Hành Giả. Quyết định ưu tiên đi Phong Tiên giới bắt đàn lớn Văn thú, bay xuyên tinh vực với tốc độ vượt âm thanh khiến tu sĩ trên đường kinh hãi."},{"chuong":1160,"tieuDe":"Mạnh Mẽ!","tomTat":"Vương Lâm phi hành tốc độ cực hạn xuyên tinh vực lục giai, khiến hơn mười lão quái chấn động bám theo quan sát mà không dám ngăn cản. Tới thất giai tinh vực đang ở trạng thái nửa phong tỏa, hắn không có ngọc giản thông hành, tăng tốc lao thẳng vào đại trận phong tỏa phá tan hoàn toàn. Bốn tu sĩ Toái Niết phóng thần thức muốn lưu hắn lại, Vương Lâm dù thương thế chưa lành vẫn thi triển Dịch Linh Ấn tạo chưởng ấn khổng lồ bao phủ cả đại lục, quét bay bốn người khiến phun máu, đánh bay đại lục trăm trượng. Chưởng ấn tiếp tục lao về phía trước đánh xuyên một đại lục hoang dã phân làm đôi. Các tông phái trên đường thấy uy lực kinh hoàng, chủ động huy động toàn lực đẩy đại lục dời đi mấy ngàn trượng nhường đường. Sau gần mười ngày dùng Dịch Linh Ấn mở đường, Vương Lâm tới được tinh vực bát giai — nơi có Phong Tiên giới."},{"chuong":1161,"tieuDe":"Con Rết Lửa","tomTat":"Sau hai mươi ngày phi hành liên tục, Dịch Linh Ấn của Vương Lâm đã đạt cực hạn hấp thu sức mạnh thiên địa, hắn chặt đứt sự hấp thu và dùng ấn mở đường tiến về bát giai tinh vực. Trước mặt là Loạn Thú Vụ Giới — tầng sương mù dày đặc bao quanh bát giai tinh vực, bên trong đầy mãnh thú cấp mười trở lên, Thần Tông đã mở bốn con đường an toàn nhưng Vương Lâm không biết đường nào. Hắn bỏ qua con đường mơ hồ biết được từ thời ở Bồng Lai vì quá xa và không chắc chắn, quyết định xông thẳng vào sương mù. Trên con đường thứ ba, một lão giả Vô Cực Tông tu vi Toái Niết đại viên mãn đẩy ba đệ tử Tịch Niết vào sương mù chiến đấu mãnh thú để cảm ngộ thiên đạo. Vương Lâm dùng Dịch Linh Ấn mở đường, bị con rết đỏ cấp mười một chặn đường nhưng dập tắt biển lửa của nó dễ dàng. Sáu con rết đỏ khác và một con rết lam cấp mười hai dài gần ngàn trượng lao tới bao vây. Lão giả Vô Cực Tông nghe tiếng gầm kinh ngạc lo đệ tử gặp nguy, lập tức lao vào sương mù. Vương Lâm phân tích chiến thuật hiệp đồng của bầy rết, quyết định phản kích giết mãnh thú đuổi theo để tránh bại lộ vị trí."},{"chuong":1162,"tieuDe":"Kinh Sợ","tomTat":"Vương Lâm kích hoạt quy tắc lửa — chu tước thức tỉnh lần ba dung nhập quy tắc thiên địa — diệt hàng loạt rết cấp 12 chỉ bằng một chỉ, đại khai sát giới quét sạch mãnh thú cản đường. Con rết lam nghìn trượng cấp 12 thi triển phương pháp thoát xác quỷ dị, thân nhỏ dần nhưng tốc độ tăng gấp bội liên tục truy đuổi. Bốn ngày xuyên Loạn Thú Vụ Giới theo Dịch Linh Ấn mở đường máu, Vương Lâm tiếp cận biên giới tầng tám tinh vực. Tại biên giới, hắn triệu biển lửa lam thẫm ngưng tụ thành chu tước lam đại chiến rết lam ba trăm trượng (sau nhiều lần thoát xác), hai ngọn lửa va chạm gây nổ kinh thiên, rết bị nổ nửa thân bỏ chạy. Trận chiến gây chấn động khiến khí tức cấp 13 từ chỗ sâu nhất Loạn Thú Vụ Giới quét ra áp chế tất cả mãnh thú. Lão già đạo bào Vô Cực Tông ẩn quan sát, kinh sợ nhận xét ngọn lửa Vương Lâm hơn cả Hỏa Ngô Linh, nhận ra thứ hắn thi triển không phải Dịch Linh Ấn thật và hắn không phải người Thần Tông. Khi khí tức cấp 13 quét tới, lão biến sắc cuốn ba đệ tử rời đi, chấm dứt tập luyện tại đây."},{"chuong":1163,"tieuDe":"Phong Động","tomTat":"Rời Loạn Thú Vụ Giới, Vương Lâm bước vào bát giai tinh vực, cảm nhận luồng khí tức cấp mười ba nên bỏ qua con rết, ưu tiên tiến về Phong Tiên Giới. Sau gần một tháng thu liễm thân hình vòng tránh các tông phái, hắn tới gần lối vào Phong Tiên Giới đã tàn phá mà không ai hay biết, xuất hiện từ sương mù trước hơn mười tu sĩ. Tại tầng năm, Lữ Yên Phi đứng trên ngọn núi Quy Nguyên Tông chờ Vương Lâm suốt trăm năm không thấy, kiên quyết cắt quan hệ sư đồ với Tôn Vân rồi cùng ba sư huynh truyền tống đến chủ tông Vô Cực Tông dự cuộc so tài phân tông, rơi lệ nói rằng khi Vương Lâm trở về thì Quy Nguyên Tông có lẽ không còn. Ở tầng chín, Lý Thiến Mai lau máu thú sau trận thú triều tại chiến trường Yêu Tông, bất chấp cảnh cáo đào ngũ kiên quyết rời đi ba tháng vì tin Vương Lâm sẽ giữ lời hứa trăm năm trợ giúp Quy Nguyên Tông, được thân ảnh nhượng bộ đưa ngọc bội dùng truyền tống trận. Mộc Băng Mi ẩn trong động phủ trên đại lục hoang dã Vân Hải, thương thế chưa khỏi, hồi tưởng về phân thân Liễu Mi đặc biệt đến mức khiến nàng không phân biệt được mình là ai, nước mắt nguyên thần chảy xuống. Nữ tử Vương San San từ Thần Tông đến đón nàng về theo lệnh gia sư, đề nghị cùng đi xem cuộc so tài tông phái."},{"chuong":1164,"tieuDe":"Nghênh Đón","tomTat":"Vương Lâm tới bên ngoài khe khổng lồ dẫn vào Phong Tiên Giới tại bát giai tinh vực, nơi đại hội bắt buộc tông phái tầng tám tham dự đang diễn ra. Tại đây hơn mười tu sĩ tiểu bối do Lý Nguyên Lôi (Tịch Niết hậu kỳ đại viên mãn) dẫn đầu đang chờ đợi thêm đồng bạn. Vương Lâm tản thần thức vào khe, thoáng thấy thế giới tràn đầy ánh sáng vàng bị cuồng phong bao phủ rồi thần thức bị nuốt tiêu tan, bị nhóm tu sĩ chế nhạo là ngông cuồng. Lý Nguyên Lôi mời hợp tác nhưng Vương Lâm lạnh nhạt từ chối, định tự mình tiến vào. Khi Vương Lâm sắp bước vào khe, hơn một trăm con Văn Thú đỏ thẫm to trăm trượng cùng sương đỏ phun ra dữ tợn, nhóm tu sĩ vội thắp Tế Thiên Hương xua đuổi. Giữa đàn Văn Thú hung ác, Vương Lâm xuất hiện cưỡi trên một Văn Thú đặc biệt toàn thân vàng nhạt — toàn bộ Văn Thú đỏ lập tức lộ vẻ cung kính né tránh, vờn quanh hộ tống hắn tiến vào Phong Tiên Giới. Cảnh tượng này khiến nhóm tu sĩ kinh hãi da đầu tê dại, vì Văn Thú được coi là không thể thuần hóa, ngay cả Thần Tông phái đại thần thông tu sĩ vào cũng toàn bộ thất bại."},{"chuong":1165,"tieuDe":"Tập Hợp Văn Thú Màu Đỏ Thẫm","tomTat":"Khe nứt Phong Tiên Giới mở ra, nuốt lấy tất cả sinh linh tiến vào bên trong. Bên trong tràn ngập hào quang vàng, sương mù đỏ quỷ dị, tiên khí nồng đậm cùng gió vô biên vô tận — nhẹ thì thoải mái, mạnh thì có thể phá nát thân thể đập vỡ nguyên thần, kèm tiếng than thảm thiết quỷ dị vang vọng. Vương Lâm triệu hồi Văn Thú của mình — đã lột xác thành Văn Thú Vương màu vàng nhạt — lập tức khiến hơn trăm Văn Thú đỏ tại khe nứt lao tới nghênh đón thần phục như đón vua. Văn Thú Vương hưng phấn ngửa mặt kêu dài, triệu tập thêm hơn trăm Văn Thú từ sương đỏ, tất cả đồng loạt run rẩy thần phục. Vương Lâm nhận ra mỗi con Văn Thú đỏ nơi đây thực lực tương đương tu sĩ Khuy Niết, trong đó loại màu đỏ sẫm ngang Khuy Niết hậu kỳ, và đây mới chỉ là ngoại vi Phong Tiên Giới."},{"chuong":1166,"tieuDe":"Một Văn Thú Vương Khác (1)","tomTat":"Vương Lâm mất hai ngày bay vòng quanh ngoại vi Phong Tiên Giới, thu hoạch nhiều tiên ngọc và Văn Thú từ các đám sương đỏ, nhưng nhận ra nguồn Văn Thú bị gió thổi ra ngoại vi ngày càng cạn kiệt. Hắn dùng Văn Thú Vương phát tiếng rống triệu hồi, thu phục thêm gần nghìn Văn Thú đợt đầu, trong đó gần trăm con đỏ thẫm thần phục, nhưng hơn mười con mạnh hơn bỏ trốn. Ngay lúc đó, đàn Văn Thú mấy vạn con ầm ầm bay tới, trong đó có Văn Thú lam khí tức ngang Tịch Niết và khoảng ba trăm Văn Thú trắng gần trong suốt phát ra khí tức Toái Niết. Vương Lâm dùng hai nghìn Văn Thú đã thu phục vây quanh ẩn thân, sai Văn Thú Vương dẫn đám tùy tùng bay tránh, đại đàn không phát hiện tung tích rồi quay về. Hắn suy ngẫm về nguồn gốc bí ẩn của Văn Thú Vương lấy từ Chu Tước Tinh và sự chênh lệch thực lực so với Văn Thú cùng cấp trong Phong Tiên Giới. Nhận thấy chiến thuật dụ dỗ ra ngoại vi quá nguy hiểm, Vương Lâm quyết định mang hai nghìn Văn Thú chậm rãi tiến sâu vào Phong Tiên Giới tùy cơ ứng biến."},{"chuong":1167,"tieuDe":"Một Văn Thú Vương Khác (2)","tomTat":"Ngày thứ năm trong Phong Tiên Giới, Vương Lâm phát hiện một Văn Thú lam đơn độc cảnh giới Tịch Niết sơ kỳ gần mảnh vỡ đại lục trôi nổi. Dùng uy áp Văn Thú Vương khuất phục nó, rồi đọc ký ức bằng thần thức, biết phía trước có một Văn Thú Vương khác. Hắn nảy ra kế hoạch lớn: giết các Văn Thú Vương khác, cho Văn Thú Vương của mình hấp thụ để thao túng toàn bộ Văn Thú thuộc hạ của chúng. Vương Lâm phóng quy tắc chi tinh từ mi tâm in lên Văn Thú Vương, nguyên thần dung nhập vào điều khiển, phong ấn uy áp ngụy trang nó thành Văn Thú lam bình thường, rồi giao thân xác cho gần hai nghìn Văn Thú bảo vệ. Điều khiển Văn Thú Vương tiến sâu, dọc đường gặp nhiều đàn Văn Thú lam hàng trăm con, có con ngang Tịch Niết hậu kỳ, không bị phát hiện. Hắn nhận định nơi sâu trong Phong Tiên Giới ngay cả tu sĩ thiên nhân suy kiếp cũng khó sống sót. Cuối cùng tìm đến dãy núi khổng lồ ở rìa mảnh vỡ đại lục, là lãnh địa của Văn Thú Vương khác, phát hiện hai con Văn Thú trắng cấp cao bám trên vách núi."},{"chuong":1168,"tieuDe":"Tới Gần","tomTat":"Văn Thú Vương (do nguyên thần Vương Lâm điều khiển) đã biến thành màu lam, bay vào vùng đất Văn Thú gần dãy núi. Đàn Văn Thú màu đỏ nhường đường trước uy áp, nhưng mấy trăm con Văn Thú lam nhận ra kẻ lạ và thù địch tấn công. Văn Thú Vương dùng xúc tu kết hợp quy tắc chi tinh hạ sát liên tiếp bốn con Văn Thú lam, hút sạch tinh hoa huyết dịch. Tống Lạc Hải, trưởng lão Tịch Hồn Đạo tu vi Toái Niết trung kỳ, đã ẩn nấp ba tháng nơi đây để bắt Văn Thú Vương kiểm chứng suy đoán bí ẩn, nhưng bị hai con Văn Thú trắng xuất hiện khiến tiến thoái lưỡng nan. Một trong hai Văn Thú trắng lao ra tấn công Văn Thú Vương, hai bên va chạm mấy chục lần đều bị thương, Văn Thú trắng thi triển thần thông tách lông bắn ra như phi kiếm, Văn Thú Vương quan sát rồi học theo đối công. Đúng lúc giao chiến, dãy núi nứt toác từ đỉnh đến chân, sương tím tràn ra, một con Văn Thú Vương toàn thân màu tím to trăm trượng chậm rãi bay ra — chúa thật của vùng này. Uy áp của nó khiến tất cả Văn Thú khuất phục, thoáng nhìn chỗ ẩn thân của Tống Lạc Hải rồi dừng mắt trên Văn Thú Vương (Vương Lâm), truyền ra một tiếng kêu khẽ."},{"chuong":1169,"tieuDe":"Tân Vương!","tomTat":"Văn Thú Vương màu tím (Toái Niết trung kỳ) phát tiếng kêu vương giả nhằm thu phục Văn Thú của Vương Lâm vào đàn, nhưng Văn Thú giả vờ thần phục tiếp cận gần. Vương Lâm nguyên thần hiện ra, dùng cuồng phong cuốn bay hai Văn Thú trắng hộ vệ, liên tục điểm bốn chỉ tạo bốn dấu ấn quy tắc chi tinh hợp thành quy tắc thủ, in thủ ấn lên mi tâm Văn Thú Vương màu tím khiến nó trọng thương nặng. Văn Thú Vương màu tím lui về phía sau dùng sương tím trị thương, đồng thời mấy trăm Văn Thú lam và mấy nghìn Văn Thú đỏ thẫm vây công Vương Lâm. Văn Thú của Vương Lâm bùng phát kim quang vạn dặm, phát tiếng kêu vương giả, tiến hóa thành Văn Thú Vương mới, khiến toàn bộ đàn Văn Thú kính sợ ngừng chiến. Vương Lâm thi triển Định Thân Thuật dẫn tiên lực Phong Tiên Giới khóa chặt Văn Thú Vương màu tím, để Văn Thú dùng xúc tu hấp thụ toàn bộ tinh hoa đối phương — Văn Thú Vương mới chính thức ra đời. Tống Lạc Hải ẩn mình chứng kiến toàn bộ, nhận ra nguyên thần tu sĩ ẩn trên thân Văn Thú Vương, ánh mắt lóe lên đầy toan tính."}];
